    let sessionToken = null;

    // [FIX] gasCall dengan retry dan timeout diperpanjang
    async function gasCall(fn, args = [], retry = 1) {
      return new Promise((resolve, reject) => {
        const cb = 'cb_' + Date.now() + '_' + Math.floor(Math.random() * 1e6);
        const url = getGasUrl() + '?fn=' + encodeURIComponent(fn) + '&args=' + encodeURIComponent(JSON.stringify(args)) + '&token=' + encodeURIComponent(sessionToken || '') + '&callback=' + cb + '&t=' + Date.now();
        const script = document.createElement('script');
        let done = false;
        const timer = setTimeout(() => {
          if (done) return;
          done = true;
          script.src = '';
          if (script.parentNode) script.parentNode.removeChild(script);
          delete window[cb];
          if (retry > 0) {
            console.warn(`GAS timeout, retry ${retry}...`);
            gasCall(fn, args, retry - 1).then(resolve).catch(reject);
          } else {
            reject(new Error('GAS timeout atau tidak merespon. Cek URL dan pastikan sudah deploy sebagai Web App dengan akses "Anyone".'));
          }
        }, 20000); // timeout 20 detik
        window[cb] = function(r) {
          if (done) return;
          done = true;
          clearTimeout(timer);
          if (script.parentNode) script.parentNode.removeChild(script);
          delete window[cb];
          if (r && r.ok) resolve(r.data);
          else {
            const errMsg = (r && r.error) || 'GAS error: tidak ada respon valid';
            if (fn !== 'login' && (errMsg.indexOf('SESSION_INVALID') >= 0 || errMsg.indexOf('SESSION_EXPIRED') >= 0)) {
              forceReLogin_('Sesi login sudah habis. Silakan login lagi.');
            }
            reject(new Error(errMsg));
          }
        };
        script.async = true;
        script.src = url;
        // [NEW] Deteksi gagal load lebih cepat (URL salah/tidak bisa diakses/network error) tanpa menunggu 20 detik
        script.onerror = () => {
          if (done) return;
          done = true;
          clearTimeout(timer);
          if (script.parentNode) script.parentNode.removeChild(script);
          delete window[cb];
          if (retry > 0) {
            console.warn(`GAS gagal dimuat (kemungkinan URL salah/tidak bisa diakses), retry ${retry}...`);
            gasCall(fn, args, retry - 1).then(resolve).catch(reject);
          } else {
            reject(new Error('GAS gagal dimuat. Kemungkinan URL Web App salah, deployment tidak aktif, atau tidak ada koneksi internet. Cek URL: ' + getGasUrl()));
          }
        };
        document.head.appendChild(script);
      });
    }

