    // [NEW] Khusus untuk kirim foto (base64 besar). gasCall (JSONP/GET) tidak dipakai di sini karena
    // data foto dimasukkan ke query string URL, dan base64 foto (ratusan KB - 1.5MB) jauh melebihi batas
    // panjang URL yang diizinkan browser/server (hanya beberapa KB) -> <script> gagal load -> muncul
    // error "GAS gagal dimuat". Fungsi ini mengirim lewat fetch POST (body request, bukan URL) supaya
    // tidak kena limit tersebut. Memakai Content-Type text/plain agar tidak memicu CORS preflight
    // (teknik standar untuk POST ke GAS Web App). Endpoint dan parameter (fn/args) sama seperti gasCall,
    // tinggal pastikan GAS punya fungsi doPost yang meneruskan ke router yang sama dengan doGet.
    async function gasUploadFoto(fn, args = []) {
      const resp = await fetch(getGasUrl(), {
        method: 'POST',
        headers: { 'Content-Type': 'text/plain;charset=utf-8' },
        body: JSON.stringify({ fn, args, token: sessionToken || '' })
      });
      if (!resp.ok) throw new Error('GAS gagal merespon (HTTP ' + resp.status + ').');
      const r = await resp.json();
      if (r && r.ok) return r.data;
      const errMsg = (r && r.error) || 'GAS error: tidak ada respon valid';
      if (errMsg.indexOf('SESSION_INVALID') >= 0 || errMsg.indexOf('SESSION_EXPIRED') >= 0) {
        forceReLogin_('Sesi login sudah habis. Silakan login lagi.');
      }
      throw new Error(errMsg);
    }


