    let _syncInterval = null; // sudah tidak dipakai untuk start, cuma dijaga supaya stopAutoSync() tetap aman
    
    // [NEW] Pull-to-refresh handler
    // [PERF-FIX] Sebelumnya listener touchmove ini { passive:false } + memanggil
    // e.preventDefault() di dalamnya. Non-passive touchmove pada container yang
    // di-scroll vertikal itu memaksa browser menunggu JS selesai jalan SEBELUM
    // boleh mulai scroll di compositor thread - ini penyebab utama scroll terasa
    // berat/patah-patah di HP RAM kecil, karena kejadian di HAMPIR SETIAP scroll
    // (setiap kali mulai scroll dari paling atas). Diganti jadi passive:true (scroll
    // native jalan mulus tanpa nunggu JS), efek "rubber-band" browser ditahan lewat
    // CSS overscroll-behuh (lihat index.html) alih-alih lewat preventDefault manual.
    // Update indikator visualnya juga di-throttle ke requestAnimationFrame supaya
    // tidak menulis ulang DOM di SETIAP event touchmove (bisa puluhan kali/detik).
    let _pullStartY = 0, _pullCurrentY = 0, _pulling = false, _pullRafPending = false;
    function initPullToRefresh() {
      const content = document.querySelector('.content-area');
      if (!content) return;
      content.addEventListener('touchstart', e => {
        if (content.scrollTop === 0) {
          _pullStartY = e.touches[0].clientY;
          _pulling = true;
        }
      }, { passive: true });
      content.addEventListener('touchmove', e => {
        if (!_pulling) return;
        _pullCurrentY = e.touches[0].clientY;
        if (_pullRafPending) return;
        _pullRafPending = true;
        requestAnimationFrame(() => {
          _pullRafPending = false;
          const diff = _pullCurrentY - _pullStartY;
          if (diff > 0 && diff < 150) {
            let indicator = document.getElementById('pull-indicator');
            if (!indicator) {
              indicator = document.createElement('div');
              indicator.id = 'pull-indicator';
              indicator.style.cssText = 'text-align:center;padding:10px;color:var(--biru);font-size:12px;font-weight:600;';
              content.insertBefore(indicator, content.firstChild);
            }
            indicator.innerHTML = diff > 80 ? '<i class="fas fa-check"></i> Lepas untuk refresh' : '<i class="fas fa-arrow-down"></i> Tarik untuk refresh';
          }
        });
      }, { passive: true });
      content.addEventListener('touchend', async () => {
        if (!_pulling) return;
        _pulling = false;
        const diff = _pullCurrentY - _pullStartY;
        let indicator = document.getElementById('pull-indicator');
        if (indicator) {
          indicator.remove();
          indicator = null;
        }
        if (diff > 80) {
          await refreshDataFromServer(true);
          if (currentPage === 'rekap') loadRekap();
          else if (currentPage === 'dashboard') loadDashboard();
          else if (currentPage === 'penjualan') loadPenjualan();
          else if (currentPage === 'transaksi') loadTransaksi();
          else if (currentPage === 'stockbarang') loadStockBarang();
          else if (currentPage === 'produk') loadProduk();
          else if (currentPage === 'pelanggan') loadPelanggan();
          else if (currentPage === 'piutang') loadPiutang();
        }
        _pullStartY = 0;
        _pullCurrentY = 0;
      });
    }
    // [NEW-FIX] Fallback drag-scroll horizontal khusus untuk .menu-tabs (baris tab menu),
    // untuk tablet/browser yang native touch-scroll overflow-x-nya tidak jalan (vertikal
    // content-area sudah normal, tapi horizontal menu-tabs masih macet di beberapa tablet).
    // Pakai event delegation di document (bukan di #menuTabs langsung) supaya tetap jalan
    // walau isi #menuTabs di-render ulang oleh renderMenuTabs() yang sudah ada.
    // Klik tab tetap berfungsi normal seperti biasa: drag-scroll hanya aktif kalau gerakan
    // horizontal melewati ambang batas (bukan sekadar tap), dan klik yang menyusul persis
    // setelah drag akan diblok supaya tidak salah pindah menu.
    // [PERF-FIX] Sebelumnya tabsElFrom() (yang isinya e.target.closest('.menu-tabs'),
    // sebuah pencarian ke atas DOM tree) dipanggil di SETIAP event touchmove di
    // SELURUH halaman - termasuk saat scroll konten yang sama sekali tidak ada
    // hubungannya dengan menu tab. Di HP RAM kecil, closest() yang jalan puluhan
    // kali/detik selama scroll mana pun ikut menambah beban CPU tiap frame.
    // Sekarang closest() cuma dipanggil SEKALI di touchstart; selama drag berjalan,
    // move() pakai referensi dragEl yang sudah disimpan, tidak query ulang.
    (function initMenuTabsDragScroll(){
      let dragEl=null, startX=0, startScrollLeft=0, moved=false, isDown=false, justDragged=false;
      const THRESHOLD = 8;
      function tabsElFrom(t){ return (t && t.closest) ? t.closest('.menu-tabs') : null; }
      function down(x, el){ isDown=true; moved=false; dragEl=el; startX=x; startScrollLeft=el.scrollLeft; }
      function move(x){ if(!isDown||!dragEl) return; const diff=x-startX; if(Math.abs(diff)>THRESHOLD){ moved=true; dragEl.scrollLeft = startScrollLeft - diff; } }
      function up(){ if(moved){ justDragged=true; setTimeout(()=>{ justDragged=false; }, 300); } isDown=false; moved=false; dragEl=null; }
      document.addEventListener('touchstart', e=>{ const el=tabsElFrom(e.target); if(el) down(e.touches[0].clientX, el); }, { passive:true });
      document.addEventListener('touchmove', e=>{ if(isDown) move(e.touches[0].clientX); }, { passive:true });
      document.addEventListener('touchend', ()=>{ up(); }, { passive:true });
      document.addEventListener('mousedown', e=>{ const el=tabsElFrom(e.target); if(el) down(e.clientX, el); });
      document.addEventListener('mousemove', e=>{ if(isDown) move(e.clientX); });
      document.addEventListener('mouseup', ()=>{ up(); });
      document.addEventListener('click', e=>{ if(justDragged && tabsElFrom(e.target)){ e.preventDefault(); e.stopPropagation(); } }, true);
    })();
    function loadLocalData() {
      const s = localStorage.getItem('tirtaFullData');
      if (s) { try { const d = JSON.parse(s); products = d.products || []; pelanggan = d.pelanggan || []; allTrxList = d.allTrxList || []; allCustomers = d.allCustomers || []; stockInHistory = d.stockInHistory || []; setoranHistory = d.setoranHistory || []; drivers = d.drivers || ['oji','padong','said','dedi','zehpudin']; settings = { ...settings, ...(d.settings || {}) }; allUsers = d.allUsers || []; masterStockHistory = d.masterStockHistory || {}; } catch(e) {} }
      if (products.length === 0) products = [ { sku:'aq1500', nama:'Aqua 1500 ml', modal:50000, jual:55000, stokAwal:0 }, { sku:'aq200', nama:'Aqua 200 ml', modal:33000, jual:40000, stokAwal:3 }, { sku:'aq220b', nama:'Aqua Cube', modal:21000, jual:38000, stokAwal:0 }, { sku:'aq330', nama:'Aqua 330 ml', modal:35000, jual:42000, stokAwal:29 }, { sku:'aq600', nama:'Aqua 600 ml', modal:44000, jual:49000, stokAwal:0 }, { sku:'aqg', nama:'Aqua Galon 19L', modal:16750, jual:23000, stokAwal:5 } ];
      if (pelanggan.length === 0) pelanggan = ['Winda','ko asun'];
      if (allCustomers.length === 0) allCustomers = pelanggan.slice();
      if (!settings.salesList) settings.salesList = [];
      if (allUsers.length === 0) allUsers = [
        { name:'admin', role:'admin' },
        { name:'hasan', role:'sales' },
        { name:'ujang', role:'sales' },
        { name:'oji', role:'driver' },
        { name:'padong', role:'driver' },
        { name:'said', role:'driver' },
        { name:'dedi', role:'driver' },
        { name:'tirta', role:'admin' }
      ];
      const _masterUsers = [
        { name:'admin', role:'admin' },
        { name:'hasan', role:'sales' },
        { name:'ujang', role:'sales' },
        { name:'oji', role:'driver' },
        { name:'padong', role:'driver' },
        { name:'said', role:'driver' },
        { name:'dedi', role:'driver' },
        { name:'tirta', role:'admin' }
      ];
      _masterUsers.forEach(mu => { if (!allUsers.find(u => u.name === mu.name)) allUsers.push(mu); });
      _logoUrl = localStorage.getItem('tirtaLogo') || EMBEDDED_LOGO; // [UPDATED] fallback ke logo tertanam
      _qrisUrl = settings.qris || localStorage.getItem('sp_qris') || EMBEDDED_QRIS;
    }

    let _syncCountdown = 0;
    function updateSyncCountdown() {
      const el = document.getElementById('syncStatus');
      if (el) el.textContent = '🔄 Manual';
    }

    // [FIX] syncFromGAS dengan error handling lebih baik
    async function syncFromGAS() {
      const el = document.getElementById('syncStatus');
      if (el) el.textContent = '🔄 Sync...';
      _syncCountdown = 30;
      const _oldTrxIds = new Set(allTrxList.map(t => t.id));
      const _oldStockGroupIds = new Set(stockInHistory.map(e => e.groupId));
      try {
        const [prod, cust, trx, set, users, stockIn, gasDrivers] = await Promise.all([
          gasCall('getProducts', []), gasCall('getCustomers', []),
          gasCall('getTrxList', []), gasCall('getSettings', []), gasCall('getUsers', []),
          gasCall('getInputBarangHistory', []), gasCall('getDrivers', [])
        ]);
        if (Array.isArray(prod)) products = prod;
        if (Array.isArray(cust)) { allCustomers = cust; pelanggan = cust.slice(); }
        if (Array.isArray(trx)) {
          const localMap = new Map(allTrxList.map(t => [t.id, t]));
          allTrxList = trx.map(t => {
            const existing = localMap.get(t.id);
            return existing && Array.isArray(existing.items) ? { ...t, items: existing.items } : t;
          });
          allTrxList.sort((a, b) => (b.tgl || '').localeCompare(a.tgl || '') || (b.id || '').localeCompare(a.id || ''));
        }
        if (set && typeof set === 'object') {
          settings.namaToko = set.storeName || settings.namaToko;
          settings.alamat = set.address || settings.alamat;
          settings.tagline = set.tagline || settings.tagline;
          settings.bottomLine = set.footer || settings.bottomLine;
          settings.telepon = set.phone || settings.telepon;
          settings.bank1 = set.bank1 || settings.bank1;
          settings.bank2 = set.bank2 || settings.bank2;
          settings.salesList = Array.isArray(set.salesList) ? set.salesList : [];
        }
        if (Array.isArray(stockIn) && stockIn.length > 0) {
          stockInHistory = stockIn;
        }
        if (Array.isArray(users) && users.length > 0) {
          const localMap = new Map(allUsers.map(u => [u.name, u]));
          users.forEach(u => { if (!localMap.has(u.name)) allUsers.push(u); });
          users.forEach(gasU => {
            const local = localMap.get(gasU.name);
            if (local && gasU.role) local.role = gasU.role;
          });
        }
        const _syncBuiltin = [
          { name:'admin', role:'admin' },
          { name:'hasan', role:'sales' },
          { name:'ujang', role:'sales' },
          { name:'oji', role:'driver' },
          { name:'padong', role:'driver' },
          { name:'said', role:'driver' },
          { name:'dedi', role:'driver' },
          { name:'tirta', role:'admin' }
        ];
        _syncBuiltin.forEach(mu => { if (!allUsers.find(u => u.name === mu.name)) allUsers.push(mu); });
        // Ambil drivers dari sheet Driver (prioritas) atau fallback dari allUsers
        if (Array.isArray(gasDrivers) && gasDrivers.length > 0) {
          drivers = gasDrivers;
        } else {
          const driverNames = allUsers.filter(u => u.role === 'driver').map(u => u.name);
          if (driverNames.length > 0) drivers = driverNames;
        }
        // [NEW] Deteksi transaksi/input barang baru dari device LAIN saat sync (baseline dulu di sync pertama, biar tidak spam data lama)
        const _notifBaselineDone = localStorage.getItem('tirtaNotifBaseline') === '1';
        if (!_notifBaselineDone) {
          localStorage.setItem('tirtaNotifBaseline', '1');
        } else {
          if (Array.isArray(trx)) {
            trx.filter(t => !_oldTrxIds.has(t.id)).forEach(t => addNotification('🧾', 'Transaksi Baru: '+t.id, (t.customer||'-')+' · '+(t.sales||'-')+' · '+fmtRp(t.nett||0)));
          }
          if (Array.isArray(stockIn) && stockIn.length > 0) {
            const _newGroupIds = new Set(stockIn.filter(e => !_oldStockGroupIds.has(e.groupId)).map(e => e.groupId));
            _newGroupIds.forEach(gid => { const rows = stockIn.filter(e => e.groupId === gid); addNotification('📦', 'Input Barang Baru: '+gid, (rows[0]?.driver||'-')+' · '+rows.length+' item'); });
          }
        }
        saveLocalData();
        if (currentPage === 'dashboard' || currentPage === 'transaksi' || currentPage === 'produk' || currentPage === 'gudang') renderContent();
      } catch (e) {
        console.warn('Gagal sinkron:', e);
        Swal.fire({
          icon: 'error',
          title: 'Koneksi GAGAL',
          text: e.message || 'Tidak dapat terhubung ke Google Sheets. Periksa URL GAS dan pastikan sudah di-deploy sebagai Web App dengan akses "Anyone".',
          footer: 'URL saat ini: ' + getGasUrl()
        });
      }
      const el2 = document.getElementById('syncStatus');
      if (el2) el2.textContent = '✅ Sync';
      setTimeout(()=>{ const e3=document.getElementById('syncStatus'); if(e3) updateSyncStatus(); }, 2000);
    }

    // ── AUTO SYNC 5 MENIT ──
    let _autoSyncTimer = null;
    const AUTO_SYNC_INTERVAL = 5 * 60 * 1000; // 5 menit
    let _nextSyncTime = null;

    function updateSyncStatus() {
      const el = document.getElementById('syncStatus');
      if (!el || !_nextSyncTime) return;
      const diff = Math.max(0, Math.round((_nextSyncTime - Date.now()) / 60000));
      el.textContent = diff <= 0 ? '🔄 Syncing...' : `⏱ ${diff}m`;
    }

    function startAutoSync() {
      if (_autoSyncTimer) clearInterval(_autoSyncTimer);
      _nextSyncTime = Date.now() + AUTO_SYNC_INTERVAL;
      updateSyncStatus();
      // Update countdown tiap 1 menit
      _autoSyncTimer = setInterval(async () => {
        if (Date.now() >= _nextSyncTime) {
          _nextSyncTime = Date.now() + AUTO_SYNC_INTERVAL;
          try { await syncFromGAS(); } catch(e) { console.warn('Auto sync gagal:', e); }
        }
        updateSyncStatus();
      }, 60000);
    }

    function stopAutoSync() {
      if (_autoSyncTimer) { clearInterval(_autoSyncTimer); _autoSyncTimer = null; }
      if (_syncInterval) { clearInterval(_syncInterval); _syncInterval = null; }
      const el = document.getElementById('syncStatus');
      if (el) el.textContent = 'Manual';
    }

    async function doLogin() {
      const u = document.getElementById('loginUser').value.trim(),
            p = document.getElementById('loginPass').value.trim();
      if (!u || !p) return Swal.fire('Error','Isi username & password','error');
      // [SECURITY FIX] Login sekarang diverifikasi di server (loginUser di GAS),
      // bukan dicocokkan di browser. Server tidak pernah mengirim password/hash
      // balik ke client — hanya {name, role} kalau cocok.
      // allUsers lokal di bawah ini HANYA dipakai untuk dropdown/tampilan
      // (sales, driver, dll) saat offline, TIDAK untuk verifikasi login.
      if (!allUsers || allUsers.length === 0) {
        allUsers = [
          { name:'admin', role:'admin' },
          { name:'hasan', role:'sales' },
          { name:'ujang', role:'sales' },
          { name:'oji', role:'driver' },
          { name:'padong', role:'driver' },
          { name:'said', role:'driver' },
          { name:'dedi', role:'driver' },
          { name:'tirta', role:'admin' }
        ];
      }
      Swal.fire({ title: 'Memeriksa login...', allowOutsideClick: false, didOpen: () => Swal.showLoading() });
      try {
        const f = await gasCall('login', [u, p]); // { name, role } — server yang verifikasi
        currentUser = { name: f.name, role: f.role };
        sessionToken = f.token || null;
        localStorage.setItem('tirtaUser', JSON.stringify({ ...currentUser, token: sessionToken }));
        Swal.close();
        if (isBiometricSupported() && localStorage.getItem('tirtaBioEnabled') !== '1') {
          try {
            const avail = PublicKeyCredential.isUserVerifyingPlatformAuthenticatorAvailable ? await PublicKeyCredential.isUserVerifyingPlatformAuthenticatorAvailable() : false;
            if (avail) {
              const r = await Swal.fire({ icon: 'question', title: 'Aktifkan Login Biometrik?', text: 'Buka app berikutnya cukup pakai sidik jari/Face ID, tanpa ketik ulang username/password.', showCancelButton: true, confirmButtonText: 'Aktifkan', cancelButtonText: 'Nanti saja' });
              if (r.isConfirmed) await enableBiometricLock();
            }
          } catch (bioErr) { /* diamkan - jangan ganggu alur login utama kalau cek biometrik gagal */ }
        }
        showMainApp();
      } catch (e) {
        const msg = (e && e.message) || '';
        if (msg.toLowerCase().indexOf('timeout') >= 0 || msg.toLowerCase().indexOf('gagal dimuat') >= 0 || msg.toLowerCase().indexOf('koneksi') >= 0) {
          Swal.fire('Tidak ada koneksi', 'Login butuh koneksi internet (setidaknya saat pertama kali login / setelah logout). Cek koneksi lalu coba lagi.', 'error');
        } else {
          Swal.fire('Error', 'Username/password salah!', 'error');
        }
      }
    }
    document.addEventListener('keydown', (e) => { if (e.key === 'Enter' && !document.getElementById('loginPage').classList.contains('hidden')) doLogin(); });
    function doLogout() { stopAutoSync(); localStorage.removeItem('tirtaUser'); currentUser = null; sessionToken = null; document.getElementById('loginPage').classList.remove('hidden'); document.getElementById('mainApp').classList.add('hidden'); }

    async function showMainApp() {
      document.getElementById('loginPage').classList.add('hidden'); document.getElementById('mainApp').classList.remove('hidden');
      document.getElementById('displayName').textContent = currentUser.name; document.getElementById('displayRole').textContent = currentUser.role.toUpperCase();
      document.getElementById('userAvatar').textContent = currentUser.name.charAt(0).toUpperCase();
      if (settings.alamat) document.getElementById('headerAlamat').textContent = settings.alamat;
      const _effectiveLogo = localStorage.getItem('tirtaLogo') || _logoUrl;
      if (_effectiveLogo) { _logoUrl = _effectiveLogo; document.getElementById('logoImg').src = _effectiveLogo; }
      initDarkMode(); loadNotifications(); renderMenuTabs();
      // Sync sekali saat login
      try { await syncFromGAS(); } catch(e) {}
      try { await syncSetoranHistoryFromGAS(); } catch(e) {} // [NEW] pastikan riwayat setoran juga dari Google Sheets saat login/refresh
      startAutoSync(); // argumen lama dihapus - fungsi ini sudah tidak menerima parameter, sync tiap AUTO_SYNC_INTERVAL (5 menit)
      initPullToRefresh(); // Aktifkan pull-to-refresh
      startAutoRolloverScheduler(); // [NEW] Rollover stok otomatis tiap pukul 00:00
      navigateTo('dashboard');
    }

    // [NEW] Sistem Notifikasi Aktivitas (transaksi jual baru, input barang baru, dll)
    let appNotifications = [];
    function loadNotifications() { try { appNotifications = JSON.parse(localStorage.getItem('tirtaNotifications') || '[]'); } catch(e) { appNotifications = []; } renderNotifBadge(); }
    function saveNotifications() { localStorage.setItem('tirtaNotifications', JSON.stringify(appNotifications.slice(0,10))); }
    function addNotification(icon, title, detail) {
      appNotifications.unshift({ id: Date.now()+'-'+Math.random().toString(36).slice(2,7), icon, title, detail, time: new Date().toISOString(), read: false });
      if (appNotifications.length > 10) appNotifications.length = 10; // maksimal 10, yang paling lama otomatis terbuang
      saveNotifications();
      renderNotifBadge();
    }
    function renderNotifBadge() {
      const b = document.getElementById('notifBadge');
      if (!b) return;
      const unread = appNotifications.filter(n => !n.read).length;
      if (unread > 0) { b.textContent = unread > 99 ? '99+' : unread; b.style.display = 'flex'; } else { b.style.display = 'none'; }
    }
    function showNotifications() {
      let html = '';
      if (appNotifications.length === 0) {
        html = '<p class="text-sm text-center">Belum ada notifikasi</p>';
      } else {
        html = '<div style="max-height:400px;overflow-y:auto;text-align:left;padding:2px">' + appNotifications.map(n => {
          const t = new Date(n.time);
          const timeStr = String(t.getHours()).padStart(2,'0')+':'+String(t.getMinutes()).padStart(2,'0')+' · '+String(t.getDate()).padStart(2,'0')+'/'+String(t.getMonth()+1).padStart(2,'0');
          return `<div class="clay-notif-item" style="${n.read?'opacity:0.6':''}"><div style="font-weight:700;font-size:0.8rem">${n.icon||'🔔'} ${esc(n.title)}</div><div style="font-size:0.72rem;color:var(--text2);margin-top:2px">${esc(n.detail||'')}</div><div style="font-size:0.65rem;color:var(--text3);margin-top:4px">${timeStr}</div></div>`;
        }).join('') + '</div>';
      }
      appNotifications.forEach(n => n.read = true);
      saveNotifications();
      Swal.fire({ title: '🔔 Notifikasi', html, width:'420px', confirmButtonText:'Tutup', customClass: { popup: 'clay-popup', confirmButton: 'clay-btn clay-btn-confirm' } }).then(() => renderNotifBadge());
      renderNotifBadge();
    }

    function toggleDarkMode() { document.body.classList.toggle('light-mode'); const l = document.body.classList.contains('light-mode'); localStorage.setItem('tirtaDarkMode', l ? '1' : '0'); const b = document.querySelector('.btn-darkmode'); if (b) { b.textContent = l ? '🌙' : '☀️'; b.classList.toggle('is-light', l); b.title = l ? 'Mode Gelap' : 'Mode Terang'; } }
    function initDarkMode() { if (localStorage.getItem('tirtaDarkMode') === '1') { document.body.classList.add('light-mode'); const b = document.querySelector('.btn-darkmode'); if (b) { b.textContent = '🌙'; b.classList.add('is-light'); b.title = 'Mode Gelap'; } } }

