    // ========== FOTO BUKTI ==========
    // Fungsi untuk mengkompres gambar
    async function kompresGambar(file, maxSizeKB = 1800) {
      return new Promise((resolve, reject) => {
        const reader = new FileReader();
        reader.onload = (e) => {
          const img = new Image();
          img.onload = () => {
            const canvas = document.createElement('canvas');
            let width = img.width;
            let height = img.height;
            
            // Resize jika terlalu besar (max 1920px)
            const maxDim = 1920;
            if (width > maxDim || height > maxDim) {
              if (width > height) {
                height = Math.round(height * maxDim / width);
                width = maxDim;
              } else {
                width = Math.round(width * maxDim / height);
                height = maxDim;
              }
            }
            
            canvas.width = width;
            canvas.height = height;
            const ctx = canvas.getContext('2d');
            ctx.drawImage(img, 0, 0, width, height);
            
            // Kompres dengan quality bertahap
            let quality = 0.9;
            let dataUrl = canvas.toDataURL('image/jpeg', quality);
            
            // Jika masih terlalu besar, turunkan quality
            while (dataUrl.length > maxSizeKB * 1024 && quality > 0.3) {
              quality -= 0.1;
              dataUrl = canvas.toDataURL('image/jpeg', quality);
            }
            
            resolve(dataUrl);
          };
          img.onerror = reject;
          img.src = e.target.result;
        };
        reader.onerror = reject;
        reader.readAsDataURL(file);
      });
    }

    async function uploadFotoBukti(refId, jenis, inputEl) {
      const file = inputEl.files[0];
      if (!file) return;
      
      Swal.fire({ title:'Memproses foto...', allowOutsideClick:false, didOpen:()=>Swal.showLoading() });
      
      try {
        let base64Data;
        const originalSizeKB = Math.round(file.size/1024);
        const maxSize = 1.8 * 1024 * 1024; // 1.8MB untuk buffer aman
        
        // Selalu kompres untuk memastikan ukuran aman
        base64Data = await kompresGambar(file, 1500); // Target 1.5MB setelah kompresi
        const base64Only = base64Data.split(',')[1];
        
        // Cek ukuran setelah kompresi
        const sizeAfterCompressKB = Math.round((base64Only.length * 3/4) / 1024);
        
        if (sizeAfterCompressKB > 1800) {
          // Jika masih terlalu besar, kompres lagi dengan target lebih kecil
          base64Data = await kompresGambar(file, 1000);
          base64Data = base64Data.split(',')[1];
        } else {
          base64Data = base64Only;
        }
        
        // Konversi dataURL ke blob untuk mendapatkan mime type
        const response = await fetch('data:image/jpeg;base64,' + base64Data);
        const blob = await response.blob();
        
        if (originalSizeKB > 1800) {
          Swal.fire({
            icon: 'info',
            title: 'Foto Dikompres',
            text: `Foto asli ${originalSizeKB}KB (${sizeAfterCompressKB}KB setelah kompres)`,
            timer: 2500
          });
        }
        
        const result = await gasUploadFoto('uploadFoto', [{ base64: base64Data, mimeType: 'image/jpeg', nama: refId, refId, jenis, uploader: currentUser?.name||'' }]);
        Swal.close();
        if (result && result.viewUrl) {
          Swal.fire({ icon:'success', title:'Foto berhasil diupload!', html:`<a href="${esc(result.viewUrl)}" target="_blank" style="color:var(--biru);font-weight:700">🔗 Lihat di Google Drive</a>`, confirmButtonText:'OK' });
          // Simpan link ke lokal
          const fotoKey = 'foto_'+refId;
          let fotoList = []; try { fotoList=JSON.parse(localStorage.getItem(fotoKey)||'[]'); } catch(e){}
          fotoList.push({ waktu: localDateStr()+' '+new Date().toTimeString().slice(0,8), jenis, viewUrl: result.viewUrl, thumbUrl: result.thumbUrl, nama: result.fileName, uploader: currentUser?.name||'' });
          localStorage.setItem(fotoKey, JSON.stringify(fotoList));
          return result;
        }
      } catch(e) {
        Swal.close();
        Swal.fire('Error','Gagal upload foto: '+e.message,'error');
      }
    }

