    // [NEW] Hapus foto bukti: hapus dari daftar lokal (localStorage) dan coba hapus file fisiknya di
    // Google Drive lewat GAS (fn 'deleteFoto'). Kalau backend GAS belum punya fungsi 'deleteFoto',
    // foto tetap terhapus dari daftar di web (tidak akan tampil lagi), hanya filenya saja yang
    // mungkin masih tersisa di Drive sampai fungsi 'deleteFoto' ditambahkan di backend.
    async function hapusFotoBukti(refId, viewUrl, judulEl) {
      const confirm = await Swal.fire({ title:'Hapus foto ini?', icon:'warning', showCancelButton:true, confirmButtonText:'Ya, hapus', cancelButtonText:'Batal', confirmButtonColor:'#DC2626' });
      if (!confirm.isConfirmed) return;
      const fotoKey = 'foto_'+refId;
      let fotoList = []; try { fotoList=JSON.parse(localStorage.getItem(fotoKey)||'[]'); } catch(e){}
      fotoList = fotoList.filter(f => f.viewUrl !== viewUrl);
      localStorage.setItem(fotoKey, JSON.stringify(fotoList));
      // Coba hapus file fisik di Drive juga (butuh fungsi 'deleteFoto' di GAS, lihat catatan di atas)
      const m = (viewUrl||'').match(/\/d\/([a-zA-Z0-9_-]+)/) || (viewUrl||'').match(/id=([a-zA-Z0-9_-]+)/);
      const fileId = m ? m[1] : '';
      if (fileId) { try { await gasUploadFoto('deleteFoto', [{ fileId, refId }]); } catch(e) { console.warn('deleteFoto di GAS belum tersedia/gagal:', e.message); } }
      Swal.fire({ toast:true, position:'top-end', showConfirmButton:false, timer:1500, icon:'success', title:'Foto dihapus' });
      // Update status foto kiriman kalau yang dihapus terkait transaksi yang sedang dibuka
      const statusEl = document.getElementById('fotoKirimanStatus');
      if (statusEl && refId === _currentTrxId) {
        statusEl.textContent = fotoList.length > 0 ? `✓ ${fotoList.length} foto terupload` : '';
        statusEl.style.color = 'var(--hijau)';
      }
      showFotoBukti(refId, judulEl);
    }

