    async function doRekap() {
      const tgl = document.getElementById('rekapTgl').value;
      const salesFilter = document.getElementById('rekapSales').value;
      const jenis = document.getElementById('rekapJenis').value;
      _rekapJenis = jenis;
      if (!tgl) return Swal.fire('Error','Pilih tanggal!','error');

      // [FIX] Selalu ambil data terbaru dari Google Sheets sebelum rekap
      // [FIX] loadTrxFromGAS tidak pernah didefinisikan (ReferenceError selalu terjadi, silently caught),
      // sehingga rekap selalu memakai allTrxList lama di memori/localStorage, tidak pernah ter-refresh dari server.
      // Diganti ke syncFromGAS() yang sudah ada dan benar (sama seperti dipakai untuk sync data lain).
      document.getElementById('rekapContent').innerHTML = '<div class="loading">Mengambil data dari server...</div>';
      try {
        await syncFromGAS();
      } catch(e) {
        console.warn('Gagal load dari GAS, pakai data lokal:', e);
      }

      let filtered = allTrxList.filter(t => (t.tgl||'').substring(0,10) === tgl);
      if (salesFilter) filtered = filtered.filter(t => (t.sales||'').toLowerCase().trim() === salesFilter.toLowerCase().trim());

      if (!filtered.length) {
        document.getElementById('rekapContent').innerHTML = '<div class="card"><p class="text-center text-sm">Tidak ada transaksi pada tanggal ini</p></div>';
        return;
      }

      // Laporan yang butuh items: fetch getTrxDetail per transaksi jika items belum ada
      const jenisButuhItems = ['penjualan_per_sales','rekap_per_sku','rekap_per_customer','rekap_per_qty','rekap_sales_qty','laporan_per_sales']; // [FIX] laporan_per_sales butuh items untuk hitung profit, sebelumnya tidak ada di daftar ini sehingga profit selalu salah/kosong
      // [FIX] Sebelumnya pakai .some() — kalau ADA SATU SAJA transaksi yang sudah punya cache item lokal,
      // seluruh proses ambil detail dari Sheets di-skip total, padahal transaksi LAIN yang belum punya item tetap kosong.
      // Itu sebabnya di browser biasa (ada cache lama di localStorage) datanya salah/tidak lengkap,
      // sementara di Incognito (tidak ada cache sama sekali) datanya selalu benar karena terpaksa fetch ulang semua.
      // Sekarang pakai .every(): proses fetch hanya di-skip kalau SEMUA transaksi sudah punya item.
      const adaItems = filtered.every(t => Array.isArray(t.items) && t.items.length > 0);

      if (jenisButuhItems.includes(jenis) && !adaItems) {
        document.getElementById('rekapContent').innerHTML = `<div class="loading">Mengambil detail item (0/${filtered.length})...</div>`;
        try {
          // [FIX] Fetch detail dengan batch lebih besar (50 instead of 15) untuk mempercepat
          const batchSize = 50;
          for (let i = 0; i < filtered.length; i += batchSize) {
            const batch = filtered.slice(i, i + batchSize);
            const el = document.getElementById('rekapContent');
            if (el) el.innerHTML = `<div class="loading">Mengambil detail item (${Math.min(i+batchSize, filtered.length)}/${filtered.length})...</div>`;
            await Promise.allSettled(batch.map(async trx => {
              if (Array.isArray(trx.items) && trx.items.length > 0) return;
              try {
                const detail = await gasCall('getTrxDetail', [trx.id]);
                if (detail && Array.isArray(detail.items) && detail.items.length > 0) {
                  const idx = allTrxList.findIndex(t => t.id === trx.id);
                  if (idx >= 0) allTrxList[idx].items = detail.items;
                  trx.items = detail.items;
                }
              } catch(e) { console.warn('Gagal ambil detail', trx.id, e); }
            }));
          }
          saveLocalData();
          // Re-filter setelah merge items
          filtered = allTrxList.filter(t => (t.tgl||'').substring(0,10) === tgl);
          if (salesFilter) filtered = filtered.filter(t => (t.sales||'').toLowerCase().trim() === salesFilter.toLowerCase().trim());
        } catch(e) {
          document.getElementById('rekapContent').innerHTML = `<div class="card"><p class="text-center text-sm" style="color:var(--merah)">Gagal mengambil detail item: ${esc(e.message)}</p></div>`;
          return;
        }
      }

      // Kumpulkan semua items dari filtered
      const allItems = [];
      filtered.forEach(trx => {
        (trx.items||[]).forEach(it => {
          const nettPer = it.nettPer !== undefined ? it.nettPer : ((it.harga||0)-(it.discRpPer||0));
          const profit = (nettPer - (it.modal||0)) * (it.qty||0);
          allItems.push({ customer: trx.customer, sales: trx.sales||'', sku: it.sku||'', nama: it.nama||'', qty: it.qty||0, harga: it.harga||0, discRpPer: it.discRpPer||0, modal: it.modal||0, nettPer, subtotal: nettPer*(it.qty||0), profit, status: trx.status||'' });
        });
      });

      let h = '';
      const labelFilter = `<span class="text-sm" style="color:var(--text2)">${fmtDate(tgl)}${salesFilter?' · '+salesFilter:' · Semua Sales'}</span>`;

      if (jenis === 'penjualan_per_sales') {
        // Penjualan per Sales → Customer | SKU | Total
        const salesMap = new Map();
        // Jika masih tidak ada items, fallback ke header (customer+nett per sales)
        if (allItems.length === 0) {
          filtered.forEach(trx => {
            const s = trx.sales||'Tanpa Sales';
            if (!salesMap.has(s)) salesMap.set(s, []);
            salesMap.get(s).push({ customer: trx.customer, sku: '-', subtotal: trx.nett||0 });
          });
        } else {
          allItems.forEach(item => {
            const s = item.sales || 'Tanpa Sales';
            if (!salesMap.has(s)) salesMap.set(s, []);
            salesMap.get(s).push(item);
          });
        }
        if (!salesMap.size) { h = '<div class="card"><p class="text-center text-sm">Tidak ada data</p></div>'; }
        else {
          salesMap.forEach((items, salesName) => {
            const total = items.reduce((s,it)=>s+it.subtotal,0);
            h += `<div class="card"><div class="card-title"><i class="fas fa-user-tie"></i> ${esc(salesName)}</div>${labelFilter}<div class="flex-between" style="margin-top:6px;margin-bottom:8px;font-weight:800;color:var(--biru)"><span>Total</span><span style="font-family:var(--mono)">${fmtRp(total)}</span></div>`;
            h += '<div class="table-wrap"><table><thead><tr><th>Customer</th><th>SKU</th><th style="text-align:right">Total</th></tr></thead><tbody>';
            items.forEach(it => { h += `<tr><td>${esc(it.customer)}</td><td style="font-family:var(--mono);font-size:0.65rem">${esc(it.sku)}</td><td style="font-family:var(--mono);font-weight:700;text-align:right">${fmtRp(it.subtotal)}</td></tr>`; });
            h += '</tbody></table></div></div>';
          });
        }

      } else if (jenis === 'rekap_per_sku') {
        // REKAP PER SKU → SKU | Customer | qty
        const skuMap = new Map();
        allItems.forEach(item => {
          if (!skuMap.has(item.sku)) skuMap.set(item.sku, []);
          skuMap.get(item.sku).push(item);
        });
        h = `<div class="card"><div class="card-title"><i class="fas fa-cube"></i> Rekap per SKU</div>${labelFilter}`;
        if (!skuMap.size) { h += '<p class="text-center text-sm">Tidak ada detail item tersedia</p></div>'; }
        else {
          h += '<div class="table-wrap"><table><thead><tr><th>SKU</th><th>Customer</th><th style="text-align:right">Qty</th></tr></thead><tbody>';
          Array.from(skuMap.keys()).sort().forEach(sku => {
            const items = skuMap.get(sku);
            const custAgg = {};
            items.forEach(it => { if (!custAgg[it.customer]) custAgg[it.customer]=0; custAgg[it.customer]+=it.qty; });
            const totalQty = Object.values(custAgg).reduce((s,v)=>s+v,0);
            h += `<tr style="background:var(--biru-muda)"><td colspan="2" style="font-weight:700;font-size:0.75rem">${esc(sku)}</td><td style="font-weight:800;text-align:right;color:var(--biru)">${totalQty}</td></tr>`;
            Object.entries(custAgg).sort((a,b)=>a[0].localeCompare(b[0])).forEach(([cust,qty]) => {
              h += `<tr><td></td><td>${esc(cust)}</td><td style="text-align:right">${qty}</td></tr>`;
            });
          });
          h += '</tbody></table></div></div>';
        }

      } else if (jenis === 'rekap_per_customer') {
        // REKAP PER CUSTOMER → Customer | SKU | qty | total
        // Jika tidak ada items, fallback ke header
        let h2 = `<div class="card"><div class="card-title"><i class="fas fa-users"></i> Rekap per Customer</div>${labelFilter}`;
        if (allItems.length === 0) {
          const custAgg = {};
          filtered.forEach(t => { if (!custAgg[t.customer]) custAgg[t.customer]=0; custAgg[t.customer]+=(t.nett||0); });
          h2 += '<div class="table-wrap"><table><thead><tr><th>Customer</th><th style="text-align:right">Total</th></tr></thead><tbody>';
          Object.entries(custAgg).sort((a,b)=>a[0].localeCompare(b[0])).forEach(([cust,tot]) => {
            h2 += `<tr><td>${esc(cust)}</td><td style="text-align:right;font-family:var(--mono);font-weight:700">${fmtRp(tot)}</td></tr>`;
          });
          h2 += '</tbody></table></div></div>';
        } else {
          const custMap = new Map();
          allItems.forEach(item => {
            if (!custMap.has(item.customer)) custMap.set(item.customer, []);
            custMap.get(item.customer).push(item);
          });
          if (!custMap.size) { h2 += '<p class="text-center text-sm">Tidak ada data</p></div>'; }
          else {
            h2 += '<div class="table-wrap"><table><thead><tr><th>Customer</th><th>SKU</th><th style="text-align:right">Qty</th><th style="text-align:right">Total</th></tr></thead><tbody>';
            Array.from(custMap.keys()).sort().forEach(cust => {
              const items = custMap.get(cust);
              const skuAgg = {};
              items.forEach(it => { if (!skuAgg[it.sku]) skuAgg[it.sku]={qty:0,total:0}; skuAgg[it.sku].qty+=it.qty; skuAgg[it.sku].total+=it.subtotal; });
              const grandTotal = Object.values(skuAgg).reduce((s,v)=>s+v.total,0);
              const grandQty = Object.values(skuAgg).reduce((s,v)=>s+v.qty,0);
              h2 += `<tr style="background:var(--biru-muda)"><td colspan="2" style="font-weight:700;font-size:0.75rem">${esc(cust)}</td><td style="font-weight:800;text-align:right;color:var(--biru)">${grandQty}</td><td style="font-weight:800;text-align:right;color:var(--biru);font-family:var(--mono)">${fmtRp(grandTotal)}</td></tr>`;
              Object.entries(skuAgg).sort((a,b)=>a[0].localeCompare(b[0])).forEach(([sku,v]) => {
                h2 += `<tr><td></td><td style="font-family:var(--mono);font-size:0.65rem">${esc(sku)}</td><td style="text-align:right">${v.qty}</td><td style="text-align:right;font-family:var(--mono)">${fmtRp(v.total)}</td></tr>`;
              });
            });
            h2 += '</tbody></table></div></div>';
          }
        }
        h = h2;

      } else if (jenis === 'rekap_per_qty') {
        // REKAP PER QTY → Customer | SKU | qty (diurutkan qty terbesar)
        const agg = {};
        allItems.forEach(it => {
          const key = `${it.customer}|${it.sku}`;
          if (!agg[key]) agg[key]={customer:it.customer,sku:it.sku,qty:0};
          agg[key].qty+=it.qty;
        });
        const rows = Object.values(agg).sort((a,b)=>b.qty-a.qty||a.customer.localeCompare(b.customer));
        h = `<div class="card"><div class="card-title"><i class="fas fa-sort-amount-down"></i> Rekap per Qty</div>${labelFilter}`;
        if (!rows.length) { h += '<p class="text-center text-sm">Tidak ada detail item tersedia</p></div>'; }
        else {
          h += '<div class="table-wrap"><table><thead><tr><th>Customer</th><th>SKU</th><th style="text-align:right">Qty</th></tr></thead><tbody>';
          rows.forEach(r => { h += `<tr><td>${esc(r.customer)}</td><td style="font-family:var(--mono);font-size:0.65rem">${esc(r.sku)}</td><td style="text-align:right;font-weight:700">${r.qty}</td></tr>`; });
          h += '</tbody></table></div></div>';
        }

      } else if (jenis === 'rekap_sales_qty') {
        // REKAP SALES QTY → Sales | SKU | qty
        const salesSkuAgg = {};
        allItems.forEach(it => {
          const s = it.sales||'Tanpa Sales';
          const key = `${s}|${it.sku}`;
          if (!salesSkuAgg[key]) salesSkuAgg[key]={sales:s,sku:it.sku,qty:0};
          salesSkuAgg[key].qty+=it.qty;
        });
        const rows = Object.values(salesSkuAgg).sort((a,b)=>a.sales.localeCompare(b.sales)||a.sku.localeCompare(b.sku));
        h = `<div class="card"><div class="card-title"><i class="fas fa-user-tag"></i> Rekap Sales Qty</div>${labelFilter}`;
        if (!rows.length) { h += '<p class="text-center text-sm">Tidak ada detail item tersedia</p></div>'; }
        else {
          const salesList = [...new Set(rows.map(r=>r.sales))];
          salesList.forEach(s => {
            const sRows = rows.filter(r=>r.sales===s);
            const totalQty = sRows.reduce((sum,r)=>sum+r.qty,0);
            h += `<div style="background:var(--biru-muda);padding:6px 10px;border-radius:8px;font-weight:700;font-size:0.78rem;color:var(--biru);margin-bottom:4px;display:flex;justify-content:space-between"><span>👤 ${esc(s)}</span><span>Total: ${totalQty}</span></div>`;
          });
          h += '<div class="table-wrap" style="margin-top:8px"><table><thead><tr><th>Sales</th><th>SKU</th><th style="text-align:right">Qty</th></tr></thead><tbody>';
          rows.forEach(r => { h += `<tr><td>${esc(r.sales)}</td><td style="font-family:var(--mono);font-size:0.65rem">${esc(r.sku)}</td><td style="text-align:right;font-weight:700">${r.qty}</td></tr>`; });
          h += '</tbody></table></div></div>';
        }

      } else if (jenis === 'cod' || jenis === 'transfer' || jenis === 'qris' || jenis === 'belum_transfer') {
        // COD / Transfer / QRIS / Belum Transfer → Customer | Total (dari header, selalu ada)
        // [FIX] Sebelumnya memakai field paymentMethod/statusBayar yang TIDAK PERNAH ADA di objek transaksi
        // (field yang benar & dipakai konsisten di seluruh aplikasi adalah t.status: 'cod'/'transfer'/'qris'/'belumTransfer'),
        // sehingga COD & Transfer selalu kosong dan Belum Transfer malah menampilkan SEMUA transaksi.
        const statusFiltered = filtered.filter(t => {
          const st = (t.status||'belumTransfer').toLowerCase().trim();
          if (jenis === 'cod') return st === 'cod';
          if (jenis === 'transfer') return st === 'transfer';
          if (jenis === 'qris') return st === 'qris';
          if (jenis === 'belum_transfer') return st === 'belumtransfer' || st === '';
          return false;
        });
        const statusLabel = jenis==='cod'?'COD':jenis==='transfer'?'Transfer':jenis==='qris'?'QRIS':'Belum Transfer';
        const custAgg = {};
        statusFiltered.forEach(t => {
          if (!custAgg[t.customer]) custAgg[t.customer]=0;
          custAgg[t.customer]+=(t.nett||0);
        });
        const total = statusFiltered.reduce((s,t)=>s+(t.nett||0),0);
        const rows = Object.entries(custAgg).sort((a,b)=>a[0].localeCompare(b[0]));
        h = `<div class="card"><div class="card-title"><i class="fas fa-money-bill-wave"></i> ${statusLabel}</div>${labelFilter}<div class="flex-between" style="margin-top:6px;margin-bottom:8px;font-weight:800;color:var(--biru)"><span>Total</span><span style="font-family:var(--mono)">${fmtRp(total)}</span></div>`;
        if (!rows.length) { h += '<p class="text-center text-sm">Tidak ada transaksi ' + statusLabel + '</p></div>'; }
        else {
          h += '<div class="table-wrap"><table><thead><tr><th>Customer</th><th style="text-align:right">Total</th></tr></thead><tbody>';
          rows.forEach(([cust,tot]) => { h += `<tr><td>${esc(cust)}</td><td style="text-align:right;font-family:var(--mono);font-weight:700">${fmtRp(tot)}</td></tr>`; });
          h += '</tbody></table></div></div>';
        }

      } else if (jenis === 'laporan_per_sales') {
        // LAPORAN PER SALES → Sales | SUM of total | SUM of profit (total dari header, profit dari items jika ada)
        const salesAgg = {};
        filtered.forEach(trx => {
          const s = trx.sales||'Tanpa Sales';
          if (!salesAgg[s]) salesAgg[s]={sales:s,total:0,profit:0};
          salesAgg[s].total+=(trx.nett||0);
          (trx.items||[]).forEach(it => {
            const nettPer = it.nettPer !== undefined ? it.nettPer : ((it.harga||0)-(it.discRpPer||0));
            salesAgg[s].profit += (nettPer-(it.modal||0))*(it.qty||0);
          });
        });
        const rows = Object.values(salesAgg).sort((a,b)=>a.sales.localeCompare(b.sales));
        const grandTotal = rows.reduce((s,r)=>s+r.total,0);
        const grandProfit = rows.reduce((s,r)=>s+r.profit,0);
        const hasProfit = rows.some(r=>r.profit!==0);
        h = `<div class="card"><div class="card-title"><i class="fas fa-chart-line"></i> Laporan per Sales</div>${labelFilter}<div class="flex-row" style="gap:8px;margin-top:8px;margin-bottom:8px">
          <div class="summary-box"><div style="font-size:0.65rem;color:var(--text2);font-weight:600">TOTAL PENJUALAN</div><div style="font-family:var(--mono);font-weight:800;font-size:0.9rem;color:var(--biru)">${fmtRp(grandTotal)}</div></div>
          <div class="summary-box" style="background:var(--kuning-muda)"><div style="font-size:0.65rem;color:var(--text2);font-weight:600">TOTAL PROFIT</div><div style="font-family:var(--mono);font-weight:800;font-size:0.9rem;color:var(--hijau)">${hasProfit?fmtRp(grandProfit):'—'}</div></div>
        </div>`;
        if (!rows.length) { h += '<p class="text-center text-sm">Tidak ada data</p></div>'; }
        else {
          h += '<div class="table-wrap"><table><thead><tr><th>Sales</th><th style="text-align:right">Total</th><th style="text-align:right">Profit</th></tr></thead><tbody>';
          rows.forEach(r => { h += `<tr><td style="font-weight:600">${esc(r.sales)}</td><td style="text-align:right;font-family:var(--mono);font-weight:700;color:var(--biru)">${fmtRp(r.total)}</td><td style="text-align:right;font-family:var(--mono);font-weight:700;color:var(--hijau)">${hasProfit?fmtRp(r.profit):'—'}</td></tr>`; });
          h += `<tr style="background:var(--biru-muda);font-weight:800"><td>TOTAL</td><td style="text-align:right;font-family:var(--mono);color:var(--biru)">${fmtRp(grandTotal)}</td><td style="text-align:right;font-family:var(--mono);color:var(--hijau)">${hasProfit?fmtRp(grandProfit):'—'}</td></tr>`;
          h += '</tbody></table></div></div>';
        }
      }

      document.getElementById('rekapContent').innerHTML = h || '<div class="card"><p class="text-center text-sm">Tidak ada data</p></div>';
    }

    // ========== REKAP INPUT (dengan tabel detail bisa edit qty & status) ==========
    async function loadRekapInput() { const today = localDateStr(); document.getElementById('contentArea').innerHTML = `<div class="card"><div class="flex-row mb-2"><div class="form-group col-1"><label>Tanggal</label><input type="date" id="rekapInputTgl" value="${today}"></div><button class="btn btn-primary" onclick="doRekapInput()" style="height:44px;align-self:flex-end">📊 Tampilkan</button></div></div><div id="rekapInputContent"><div class="text-center text-sm" style="padding:40px">Pilih tanggal lalu klik Tampilkan</div></div>`; await syncStockHistoryFromGAS(); doRekapInput(); }
    function doRekapInput() { const tgl = document.getElementById('rekapInputTgl').value; if (!tgl) return Swal.fire('Error','Pilih tanggal','error'); const filtered = stockInHistory.filter(s => (s.date||s.tgl||'').substring(0,10) === tgl); const data = hitungRekapLokal(filtered); renderRekapInput(data); // tambahkan tabel detail dengan fitur edit
      document.getElementById('rekapInputContent').innerHTML += buildStockDetailTableEditable(filtered);
    }
    function hitungRekapLokal(list) { const driverMap = {}; list.forEach(entry => { const driver = entry.driver || '', rit = entry.rit || '', status = (entry.status||'').toLowerCase(), sku = entry.sku || '', qty = entry.qty || 0, hargaModal = entry.hargaModal || 0, disc = entry.disc || 0, netModalPerItem = hargaModal - disc, totalRp = qty * netModalPerItem; if (!driver || !rit || !sku || qty === 0) return; if (!driverMap[driver]) driverMap[driver] = {}; if (!driverMap[driver][rit]) driverMap[driver][rit] = { totalRp: 0, kiriman: { totalRp: 0, items: {} }, titipan: { totalRp: 0, items: {} } }; driverMap[driver][rit].totalRp += totalRp; if (status === 'kiriman') { driverMap[driver][rit].kiriman.totalRp += totalRp; driverMap[driver][rit].kiriman.items[sku] = (driverMap[driver][rit].kiriman.items[sku]||0) + qty; } else if (status === 'titipan') { driverMap[driver][rit].titipan.totalRp += totalRp; driverMap[driver][rit].titipan.items[sku] = (driverMap[driver][rit].titipan.items[sku]||0) + qty; } }); const rekap = [], kiriman = [], titipan = [], kirimanQty = [], titipanQty = []; for (const d in driverMap) { for (const r in driverMap[d]) { const entry = driverMap[d][r]; rekap.push({ driver: d, rit: r, total: entry.totalRp }); if (entry.kiriman.totalRp > 0) { kiriman.push({ driver: d, rit: r, total: entry.kiriman.totalRp }); for (const sku in entry.kiriman.items) kirimanQty.push({ driver: d, rit: r, sku, qty: entry.kiriman.items[sku] }); } if (entry.titipan.totalRp > 0) { titipan.push({ driver: d, rit: r, total: entry.titipan.totalRp }); for (const sku in entry.titipan.items) titipanQty.push({ driver: d, rit: r, sku, qty: entry.titipan.items[sku] }); } } } const sum = arr => arr.reduce((s,x)=>s+x.total,0); return { rekap, grandRekap: sum(rekap), kiriman, grandKiriman: sum(kiriman), titipan, grandTitipan: sum(titipan), kirimanQty, titipanQty }; }
    function renderRekapInput(data) { let h = buildRekapTable('TOTAL Kiriman + Titipan (Rp)', data.rekap, data.grandRekap) + buildRekapTable('TOTAL KIRIMAN (Rp)', data.kiriman, data.grandKiriman) + buildRekapTable('TOTAL TITIPAN (Rp)', data.titipan, data.grandTitipan) + buildQtyTable('TOTAL KIRIMAN (QTY)', data.kirimanQty) + buildQtyTable('TOTAL TITIPAN (QTY)', data.titipanQty); document.getElementById('rekapInputContent').innerHTML = h || '<p class="text-center text-sm">Belum ada data input barang.</p>'; }
    function buildRekapTable(title, rows, grandTotal) { let html = `<div class="card"><div class="card-title"><i class="fas fa-table"></i> ${title}</div><div class="table-wrap"><table><thead><tr><th>Driver</th><th>Rit</th><th>Total</th></tr></thead><tbody>`; if (!rows || !rows.length) html += '<tr><td colspan="3" class="text-center text-sm">Tidak ada data</td></tr>'; else { rows.forEach(row => { html += `<tr><td>${esc(row.driver)}</td><td>${esc(row.rit)}</td><td style="text-align:right;font-family:var(--mono)">${fmtRp(row.total)}</td></tr>`; }); if (grandTotal !== undefined) html += `<tr style="font-weight:700;background:var(--biru-muda)"><td colspan="2">Grand Total</td><td style="text-align:right;font-family:var(--mono);color:var(--biru)">${fmtRp(grandTotal)}</td></tr>`; } html += '</tbody></table></div></div>'; return html; }
    function buildQtyTable(title, rows) { let html = `<div class="card"><div class="card-title"><i class="fas fa-list"></i> ${title}</div><div class="table-wrap"><table><thead><tr><th>Driver</th><th>Rit</th><th>SKU</th><th>Qty</th></tr></thead><tbody>`; if (!rows || !rows.length) html += '<tr><td colspan="4" class="text-center text-sm">Tidak ada数据</div></tr>'; else rows.forEach(row => { html += `<tr><td>${esc(row.driver)}</div><td>${esc(row.rit)}</div><td>${esc(row.sku)}</div><td>${row.qty}</div></tr>`; }); html += '</tbody></table></div></div>'; return html; }
    // Tabel detail input barang dengan edit qty dan status (mirip dengan di halaman Input Barang)
    function buildStockDetailTableEditable(filteredList) {
      if (!filteredList.length) return '<div class="card"><p class="text-sm text-center">Tidak ada data input barang untuk tanggal ini.</p></div>';
      let rows = filteredList.map(s => {
        const disc = s.disc || 0;
        const netModal = (s.hargaModal - disc) * s.qty;
        return `<tr>
          <td style="font-family:var(--mono);font-size:10px">${esc(s.id||'')}</td>
          <td style="white-space:nowrap">${s.date || (s.createdAt ? (s.createdAt.length > 10 ? new Date(s.createdAt).toISOString().substring(0,10) : s.createdAt.substring(0,10)) : '-')}</td>
          <td style="font-family:var(--mono);font-size:11px">${esc(s.sku)}</td>
          <td>${esc(s.nama||'')}</td>
          <td><input type="number" min="1" value="${s.qty}" style="width:60px;padding:2px 4px;font-size:11px;border:1px solid var(--border);border-radius:6px" onchange="editStockQty('${esc(s.id).replace(/'/g,"\\'")}',this.value)"></td>
          <td>${fmtRp(disc)}</td>
          <td>${fmtRp(s.hargaModal)}</td>
          <td style="font-weight:700;color:var(--biru)">${fmtRp(netModal)}</td>
          <td>${esc(s.driver||'-')}</td>
          <td>${esc(s.rit||'-')}</td>
          <td><select style="font-size:0.65rem;padding:2px 4px;border:1px solid var(--border);border-radius:6px;background:var(--surface)" onchange="editStockStatus('${esc(s.id).replace(/'/g,"\\'")}',this.value)"><option value="kiriman" ${s.status==='kiriman'?'selected':''}>Kiriman</option><option value="titipan" ${s.status==='titipan'?'selected':''}>Titipan</option></select></td>
          <td style="display:flex;gap:3px"><button class="btn btn-sm btn-primary" onclick="cetakStrukInputBarang('${esc(s.id).replace(/'/g,"\\'")}')">🧾 Cetak</button><button class="btn btn-danger btn-sm" onclick="deleteStockIn('${esc(s.id).replace(/'/g,"\\'")}')">🗑</button></td>
        </tr>`;
      }).join('');
      return `<div class="card mt-2"><div class="card-title"><i class="fas fa-clipboard-list"></i> Detail Input Barang</div><div class="table-wrap"><table><thead><tr><th>ID</th><th>Tanggal</th><th>SKU</th><th>Nama</th><th>Qty</th><th>Disc</th><th>Harga Modal</th><th>Net Modal</th><th>Driver</th><th>Rit</th><th>Status</th><th>Aksi</th></tr></thead><tbody>${rows}</tbody></tr></div></div>`;
    }

    // [NEW] Struk untuk 1 baris Detail Input Barang di Rekap Input (mirip gaya buildSetoranStrukHTML yang sudah ada, tidak menyentuhnya)
    function buildStrukInputBarangHTML(s) {
      const disc = s.disc || 0;
      const netModal = (s.hargaModal - disc) * s.qty;
      const logoHtml = _logoUrl ? `<img src="${_logoUrl}" style="width:48px;height:48px;border-radius:10px;object-fit:contain;background:#fff;padding:3px;flex-shrink:0;border:1.5px solid rgba(255,255,255,.4)">` : '<div style="width:48px;height:48px;border-radius:10px;background:rgba(255,255,255,.22);display:flex;align-items:center;justify-content:center;font-size:22px;flex-shrink:0">📦</div>';
      return `<div id="inputbarang-root" style="width:360px;background:#fff;border-radius:16px;overflow:hidden;font-family:'DM Sans',sans-serif;box-shadow:0 8px 32px rgba(29,111,164,.18)"><div style="background:linear-gradient(135deg,#1A6DB5,#2B8FDE);padding:18px 18px 14px;display:flex;align-items:center;gap:12px">${logoHtml}<div><div style="font-size:15px;font-weight:800;color:#fff;letter-spacing:-.3px">${esc(settings.namaToko||'Tirta Kencana')}</div>${settings.tagline?`<div style="font-size:11px;color:rgba(255,255,255,.75);margin-top:1px">${esc(settings.tagline)}</div>`:''}</div></div><div style="background:#EBF4FB;padding:10px 18px;display:flex;justify-content:space-between;align-items:center;font-size:11px"><div><div style="color:#7BAAC4;font-weight:700;text-transform:uppercase;letter-spacing:.8px;font-size:9px">Input Barang</div><div style="font-weight:700;color:#1D6FA4;font-size:13px">${esc(s.id||'')}</div></div><div style="text-align:right"><div style="color:#7BAAC4;font-weight:700;text-transform:uppercase;letter-spacing:.8px;font-size:9px">Tanggal</div><div style="font-weight:600;color:#0D2B3E;font-size:11px">${fmtDate(s.date||s.tgl||'')}</div></div></div><div style="padding:14px 18px"><table style="width:100%;border-collapse:collapse;margin-bottom:12px"><tr><td style="padding:6px 0;font-size:12px;color:#4A6882">SKU</td><td style="text-align:right;font-weight:600;font-size:12px;color:#0D2B3E">${esc(s.sku||'-')}</td></tr><tr><td style="padding:6px 0;font-size:12px;color:#4A6882">Nama</td><td style="text-align:right;font-weight:600;font-size:12px;color:#0D2B3E">${esc(s.nama||'-')}</td></tr><tr><td style="padding:6px 0;font-size:12px;color:#4A6882">Qty</td><td style="text-align:right;font-weight:600;font-size:12px;color:#0D2B3E">${s.qty||0}</td></tr><tr><td style="padding:6px 0;font-size:12px;color:#4A6882">Harga Modal</td><td style="text-align:right;font-size:12px;color:#0D2B3E">${fmtRp(s.hargaModal)}</td></tr><tr><td style="padding:6px 0;font-size:12px;color:#4A6882">Disc</td><td style="text-align:right;font-size:12px;color:#DC2626">-${fmtRp(disc)}</td></tr><tr><td style="padding:6px 0;font-size:12px;color:#4A6882">Driver</td><td style="text-align:right;font-size:12px;color:#0D2B3E">${esc(s.driver||'-')}</td></tr><tr><td style="padding:6px 0;font-size:12px;color:#4A6882">Rit</td><td style="text-align:right;font-size:12px;color:#0D2B3E">${esc(s.rit||'-')}</td></tr><tr><td style="padding:6px 0;font-size:12px;color:#4A6882">Status</td><td style="text-align:right;font-size:12px;font-weight:700;color:${(s.status||'').toLowerCase()==='kiriman'?'#16A34A':'#D97706'}">${esc((s.status||'-').toUpperCase())}</td></tr></table><div style="border-top:1.5px dashed #C5DFF0;padding-top:10px;display:flex;justify-content:space-between;font-size:13px;font-weight:800;color:#0D2B3E"><span>NET MODAL</span><span style="color:#1A6DB5">${fmtRp(netModal)}</span></div></div><div style="background:#EBF4FB;padding:12px 18px;text-align:center;font-size:11.5px;color:#3D6880;font-weight:600;border-top:1px dashed #C5DFF0">${esc(settings.bottomLine||'Terima kasih!')}</div></div>`;
    }

    function cetakStrukInputBarang(id) {
      const s = stockInHistory.find(x => x.id === id);
      if (!s) return Swal.fire('Error','Data input barang tidak ditemukan','error');
      _lastInputBarangStruk = s;
      const html = buildStrukInputBarangHTML(s);
      document.getElementById('strukContent').innerHTML = `<div class="modal-header"><h2>🧾 Struk Input Barang</h2><button class="modal-close" onclick="closeStruk()">✕</button></div><div class="action-grid"><div class="action-card" onclick="doInputBarangPrint()"><div style="font-size:28px">🖨️</div><div style="font-size:13px;font-weight:700">Print</div></div><div class="action-card" onclick="doInputBarangPng()"><div style="font-size:28px">📥</div><div style="font-size:13px;font-weight:700">Download PNG</div></div><div class="action-card" onclick="doInputBarangWA()"><div style="font-size:28px">💬</div><div style="font-size:13px;font-weight:700">WhatsApp</div></div><div class="action-card" onclick="document.getElementById('fotoInputBarangStruk').click()"><div style="font-size:28px">📸</div><div style="font-size:13px;font-weight:700">Upload Foto</div></div><div class="action-card" onclick="showFotoBukti('${esc(s.id).replace(/'/g,"\\'")}','Input Barang ${esc(s.id).replace(/'/g,"\\'")}')"><div style="font-size:28px">🖼</div><div style="font-size:13px;font-weight:700">Lihat Foto</div></div></div><input type="file" id="fotoInputBarangStruk" accept="image/*" capture="environment" style="display:none" onchange="uploadFotoBukti('${esc(s.id).replace(/'/g,"\\'")}','inputbarang',this)"><div style="border:1px solid var(--border);border-radius:14px;overflow:auto;max-height:480px;background:#e8f2f9;padding:14px"><div style="width:360px;margin:0 auto">${html}</div></div>`;
      document.getElementById('strukModal').classList.add('show');
    }
    function doInputBarangPrint() { if (!_lastInputBarangStruk) return; const win = window.open('','_blank','width=420,height=700'); win.document.write('<!DOCTYPE html><html><head><meta charset="UTF-8"><title>Struk Input Barang</title></head><body style="margin:16px;background:#e8f2f9;display:flex;justify-content:center">'); win.document.write(buildStrukInputBarangHTML(_lastInputBarangStruk)); win.document.write('<script>window.onload=function(){window.print();}<\/script></body></html>'); win.document.close(); }
    function doInputBarangPng() { if (!_lastInputBarangStruk) return; const off = document.getElementById('strukOffscreen'); off.style.cssText = 'position:fixed;left:-9999px;top:0;pointer-events:none;z-index:-1;background:#e8f2f9;padding:20px'; off.innerHTML = buildStrukInputBarangHTML(_lastInputBarangStruk); const el = off.querySelector('#inputbarang-root'); if (!el) return Swal.fire('Error','Gagal render','error'); setTimeout(() => { html2canvas(el, {backgroundColor:'#e8f2f9',scale:2.5,useCORS:true,allowTaint:true,logging:false}).then(canvas => { const a = document.createElement('a'); a.download = 'InputBarang-'+(_lastInputBarangStruk.id||'item')+'.png'; a.href = canvas.toDataURL('image/png'); document.body.appendChild(a); a.click(); document.body.removeChild(a); off.innerHTML = ''; Swal.fire({ toast: true, position: 'top-end', showConfirmButton: false, timer: 2000, icon: 'success', title: 'Struk tersimpan' }); }).catch(err => { off.innerHTML=''; Swal.fire('Error',err.message,'error'); }); }, 400); }
    function doInputBarangWA() { if (!_lastInputBarangStruk) return; const s = _lastInputBarangStruk; const disc = s.disc || 0; const netModal = (s.hargaModal - disc) * s.qty; let lines = ['📦 *INPUT BARANG*','*'+(settings.namaToko||'Tirta Kencana')+'*','━━━━━━━━━━']; lines.push('ID: *'+s.id+'*'); lines.push('Tgl: '+fmtDate(s.date||s.tgl||'')); lines.push('SKU: '+s.sku+' - '+(s.nama||'')); lines.push('Qty: '+s.qty); lines.push('Harga Modal: Rp '+Number(s.hargaModal||0).toLocaleString('id-ID')); if (disc) lines.push('Disc: -Rp '+Number(disc).toLocaleString('id-ID')); lines.push('Driver: '+(s.driver||'-')+' (Rit '+(s.rit||'-')+')'); lines.push('Status: *'+(s.status||'-').toUpperCase()+'*'); lines.push('━━━━━━━━━━'); lines.push('*NET MODAL : Rp '+Number(netModal).toLocaleString('id-ID')+'*'); window.open('https://wa.me/?text='+encodeURIComponent(lines.join('\n')),'_blank'); }

    // ========== INPUT BARANG ==========
    function loadInputBarang() { 
      let pOpts = '<option value="">Pilih Produk</option>'; 
      products.forEach(p => { pOpts += `<option value="${esc(p.sku)}">${esc(p.sku)} - ${esc(p.nama)}</option>`; }); 
      let dOpts = '<option value="">Pilih Driver</option>'; 
      drivers.forEach(d => { dOpts += `<option>${d}</option>`; }); 
      const inpId = 'INP-' + Date.now().toString(36).toUpperCase(); 
      _currentTrxId = inpId;
      document.getElementById('contentArea').innerHTML = 
        `<div class="card"><div class="card-title"><i class="fas fa-boxes"></i> Input Barang Masuk</div>
        <div class="form-group"><label>ID Input</label><input id="inpId" readonly value="${inpId}" style="font-family:var(--mono)"></div>
        <div class="flex-row"><div class="form-group col-1"><label>Driver *</label><select id="inpDriver">${dOpts}</select></div><div class="form-group col-1"><label>Rit *</label><input id="inpRit" placeholder="Rit"></div></div>
        <div class="form-group"><label>Status *</label><select id="inpStatus"><option value="">-- Pilih Status --</option><option value="kiriman">Kiriman</option><option value="titipan">Titipan</option></select></div>
        <div class="card" style="margin:8px 0;padding:12px 14px;background:var(--surface2);border:1px solid var(--border)">
          <div style="font-size:0.75rem;font-weight:700;color:var(--text2);margin-bottom:8px">📸 FOTO KIRIMAN (Opsional)</div>
          <div style="display:flex;gap:8px;flex-wrap:wrap;align-items:center">
            <label style="cursor:pointer;display:flex;align-items:center;gap:6px;background:var(--biru-muda);color:var(--biru);padding:8px 14px;border-radius:10px;font-size:0.75rem;font-weight:700;transition:0.2s" onmouseover="this.style.background='rgba(26,109,181,0.15)'" onmouseout="this.style.background='var(--biru-muda)'">
              <i class="fas fa-camera"></i> Kamera
              <input type="file" accept="image/*" capture="environment" style="display:none" onchange="uploadFotoKiriman(this)">
            </label>
            <label style="cursor:pointer;display:flex;align-items:center;gap:6px;background:var(--biru-muda);color:var(--biru);padding:8px 14px;border-radius:10px;font-size:0.75rem;font-weight:700;transition:0.2s" onmouseover="this.style.background='rgba(26,109,181,0.15)'" onmouseout="this.style.background='var(--biru-muda)'">
              <i class="fas fa-images"></i> Galeri
              <input type="file" accept="image/*" style="display:none" onchange="uploadFotoKiriman(this)">
            </label>
            <button class="btn btn-sm btn-ghost" style="font-size:0.7rem" onclick="showFotoBukti(_currentTrxId,'Foto Kiriman '+_currentTrxId)">🖼 Lihat Foto</button>
            <span id="fotoKirimanStatus" style="font-size:0.7rem;color:var(--text3);margin-left:auto"></span>
          </div>
        </div>
        <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:8px"><strong>📦 Item</strong><button class="btn btn-outline btn-sm" onclick="addItemInputRow()">+ Item</button></div>
        <div id="inputItemsContainer"></div>
        <div class="total-box"><div class="flex-between"><span>Total Qty</span><span id="inpTotalQty">0</span></div><div class="flex-between"><span>Gross Modal</span><span id="inpGrossModal" style="font-family:var(--mono)">Rp 0</span></div><div class="flex-between"><span>Total Disc</span><span id="inpTotalDisc" style="font-family:var(--mono);color:var(--merah)">Rp 0</span></div><div class="flex-between" style="font-size:1.1rem;font-weight:800"><span>TOTAL MODAL BERSIH</span><span id="inpNetModal" style="font-family:var(--mono);color:var(--biru)">Rp 0</span></div></div>
        <button class="btn btn-primary btn-block" onclick="saveStockIn()">💾 Simpan Input Barang</button></div>
        `; 
      addItemInputRow(); 
    }

    let _stockBarangAll = [];
    let _sbSelectedSkus = new Set();
    function toggleSbSkuDropdown() {
      const dd = document.getElementById('sbSkuDropdown');
      if (dd) dd.style.display = dd.style.display === 'none' ? 'block' : 'none';
    }
    function updateSbSkuLabel() {
      const lbl = document.getElementById('sbSkuLabel');
      if (!lbl) return;
      if (_sbSelectedSkus.size === 0) lbl.textContent = 'Semua SKU';
      else if (_sbSelectedSkus.size === 1) lbl.textContent = [..._sbSelectedSkus][0];
      else lbl.textContent = _sbSelectedSkus.size + ' SKU dipilih';
    }
    function toggleSbSku(sku) {
      if (_sbSelectedSkus.has(sku)) _sbSelectedSkus.delete(sku);
      else _sbSelectedSkus.add(sku);
      updateSbSkuLabel();
    }
    function selectAllSbSku() {
      const chks = document.querySelectorAll('#sbSkuDropdown input[type=checkbox]');
      chks.forEach(c => { _sbSelectedSkus.add(c.value); c.checked = true; });
      updateSbSkuLabel();
    }
    function clearAllSbSku() {
      _sbSelectedSkus.clear();
      const chks = document.querySelectorAll('#sbSkuDropdown input[type=checkbox]');
      chks.forEach(c => { c.checked = false; });
      updateSbSkuLabel();
    }
    async function loadStockBarang() {
      const today = localDateStr();
      _sbSelectedSkus = new Set();
      document.getElementById('contentArea').innerHTML = `
        <div class="card">
          <div class="card-title"><i class="fas fa-warehouse"></i> Stock Barang</div>
          <div class="flex-row mb-2" style="gap:8px;flex-wrap:wrap;align-items:flex-end">
            <div class="form-group col-1" style="margin:0"><label>Tanggal</label><input type="date" id="sbTgl" value="${today}"></div>
            <div class="form-group col-1" style="margin:0;position:relative">
              <label>SKU</label>
              <div id="sbSkuBtn" onclick="toggleSbSkuDropdown()" style="cursor:pointer;padding:9px 12px;border-radius:10px;border:1px solid var(--border);background:var(--surface);color:var(--text);font-size:0.8rem;display:flex;justify-content:space-between;align-items:center;gap:6px;user-select:none;">
                <span id="sbSkuLabel">Semua SKU</span><i class="fas fa-chevron-down" style="font-size:0.65rem;color:var(--text3)"></i>
              </div>
              <div id="sbSkuDropdown" style="display:none;position:absolute;top:100%;left:0;right:0;z-index:200;background:var(--card);border:1px solid var(--border);border-radius:10px;box-shadow:var(--shadow-md);max-height:220px;overflow-y:auto;padding:6px 0;">
                <div style="display:flex;gap:4px;padding:4px 8px 6px;border-bottom:1px solid var(--border);">
                  <button onclick="selectAllSbSku()" class="btn btn-sm btn-outline" style="flex:1;font-size:0.65rem;padding:4px 6px;">Semua</button>
                  <button onclick="clearAllSbSku()" class="btn btn-sm btn-ghost" style="flex:1;font-size:0.65rem;padding:4px 6px;">Reset</button>
                </div>
                <div id="sbSkuCheckList" style="padding:4px 0;"></div>
              </div>
            </div>
            <button class="btn btn-primary" onclick="toggleSbSkuDropdown();doStockBarang()" style="height:44px;align-self:flex-end">📊 Tampilkan</button>
            <button class="btn btn-warning" onclick="rolloverStokAwal()" style="height:44px;align-self:flex-end" title="Jadikan stok akhir kemarin sebagai stok awal hari ini">🔄 Rollover Stok</button>
            <button class="btn btn-outline" onclick="syncStockBarangToSheet()" style="height:44px;align-self:flex-end" title="Kirim ulang data Masuk/Keluar/Stok Akhir versi web (yang sudah benar) ke Google Sheets MasterStock">☁️ Sinkronkan ke Sheets</button>
          </div>
        </div>
        <div id="sbContent"><div class="text-center text-sm" style="padding:40px">Memuat data...</div></div>`;
      document.addEventListener('click', function _sbOutside(e) {
        const dd = document.getElementById('sbSkuDropdown');
        const btn = document.getElementById('sbSkuBtn');
        if (dd && btn && !dd.contains(e.target) && !btn.contains(e.target)) { dd.style.display = 'none'; }
      }, { capture: true });
      try {
        const data = await gasCall('getStockBarang', []);
        if (Array.isArray(data)) {
          _stockBarangAll = data;
          const skus = [...new Set(data.map(d => d.sku).filter(Boolean))].sort();
          const cl = document.getElementById('sbSkuCheckList');
          if (cl) {
            cl.innerHTML = skus.map(s => `
              <label style="display:flex;align-items:center;gap:8px;padding:6px 12px;cursor:pointer;font-size:0.78rem;font-weight:500;color:var(--text);" onmouseover="this.style.background='var(--biru-muda)'" onmouseout="this.style.background=''">
                <input type="checkbox" value="${s}" onchange="toggleSbSku(this.value)" style="width:auto;accent-color:var(--biru);cursor:pointer;"> ${s}
              </label>`).join('');
          }
        }
        doStockBarang();
      } catch(e) {
        const el = document.getElementById('sbContent');
        if (el) el.innerHTML = `<div class="card"><p class="text-center text-sm" style="color:var(--merah)">Gagal memuat data: ${e.message}</p></div>`;
      }
    }
    // [FIX] "Keluar" di menu Stock Barang selalu tampil 0 karena field d.keluar cuma dibaca mentah
    // dari getStockBarang (Sheet MasterStock), dan tidak pernah ada penulis yang mengisi nilai itu di
    // Sheet. Sesuai arahan: Keluar = total qty terjual per SKU per tanggal dari transaksi penjualan
    // (allTrxList), bukan dari Sheet. Sama seperti koreksi "masuk" yang sudah ada dari stockInHistory.
    // Transaksi kadang belum punya .items di memori (hanya ke-cache kalau Rekap sudah pernah dibuka
    // untuk tanggal itu), jadi perlu fetch getTrxDetail dulu untuk transaksi yang relevan, memakai
    // pola batching yang sama dengan doRekap().
    async function ensureTrxItemsForDates(dates) {
      const dateSet = new Set(dates);
      const relevan = allTrxList.filter(t => dateSet.has((t.tgl||'').substring(0,10)));
      const sudahLengkap = relevan.every(t => Array.isArray(t.items) && t.items.length > 0);
      if (sudahLengkap) return;
      const batchSize = 50;
      for (let i = 0; i < relevan.length; i += batchSize) {
        const batch = relevan.slice(i, i + batchSize);
        await Promise.allSettled(batch.map(async trx => {
          if (Array.isArray(trx.items) && trx.items.length > 0) return;
          try {
            const detail = await gasCall('getTrxDetail', [trx.id]);
            if (detail && Array.isArray(detail.items) && detail.items.length > 0) {
              const idx = allTrxList.findIndex(t => t.id === trx.id);
              if (idx >= 0) allTrxList[idx].items = detail.items;
              trx.items = detail.items;
            }
          } catch(e) { console.warn('Gagal ambil detail', trx.id, e); }
        }));
      }
      saveLocalData();
    }
    // Hitung total qty terjual per tanggal+SKU dari allTrxList (untuk field Keluar).
    function buildKeluarMapFromTrx(dates) {
      const dateSet = new Set(dates);
      const map = new Map();
      allTrxList.filter(t => dateSet.has((t.tgl||'').substring(0,10))).forEach(trx => {
        const tgl = (trx.tgl||'').substring(0,10);
        (trx.items||[]).forEach(it => {
          const key = tgl + '|' + (it.sku||'');
          map.set(key, (map.get(key)||0) + (it.qty||0));
        });
      });
      return map;
    }
    async function doStockBarang() {
      const dd = document.getElementById('sbSkuDropdown');
      if (dd) dd.style.display = 'none';
      const tgl = (document.getElementById('sbTgl')||{}).value || '';
      let filtered = _stockBarangAll;
      if (tgl) filtered = filtered.filter(d => (d.date||'').substring(0,10) === tgl);
      if (_sbSelectedSkus.size > 0) filtered = filtered.filter(d => _sbSelectedSkus.has(d.sku));
      // Koreksi field masuk dari stockInHistory lokal (kiriman + titipan)
      // [FIX] Sebelumnya: "masuk = localMasuk>0 ? localMasuk : d.masuk" -> kalau hari itu SKU tertentu
      // CUMA ada entri 'titipan' (tanpa 'kiriman' sama sekali), localMasuk hasilnya 0 (BENAR, titipan
      // memang tidak dihitung), tapi karena 0 dianggap "kosong" kode malah jatuh ke fallback d.masuk
      // (angka lama dari Sheets yang salah/ketinggalan jaman, dari sebelum aturan kiriman-saja ada).
      // Perbaikan: fallback ke d.masuk HANYA kalau memang tidak ada record lokal sama sekali (kiriman
      // ATAU titipan) untuk tanggal+SKU itu -> berarti data lokal belum sinkron, baru percaya ke GAS.
      const tanggalRelevan = [...new Set(filtered.map(d => (d.date||'').substring(0,10)).filter(Boolean))];
      await ensureTrxItemsForDates(tanggalRelevan);
      const keluarMap = buildKeluarMapFromTrx(tanggalRelevan);
      filtered = filtered.map(d => {
        const recordsForDate = stockInHistory.filter(s => (s.date||s.tgl||'').substring(0,10) === (d.date||'').substring(0,10) && s.sku === d.sku);
        const localMasuk = recordsForDate.filter(s => (s.status||'').toLowerCase() === 'kiriman').reduce((sum, s) => sum + (s.qty||0), 0);
        const masuk = recordsForDate.length > 0 ? localMasuk : (d.masuk||0);
        const keluar = keluarMap.get((d.date||'').substring(0,10) + '|' + d.sku) || 0;
        return { ...d, masuk, keluar, stokAkhir: (d.stokAwal||0) + masuk - keluar };
      });
      const el = document.getElementById('sbContent');
      if (!el) return;
      if (!filtered.length) { el.innerHTML = '<div class="card"><p class="text-center text-sm">Tidak ada data untuk filter ini.</p></div>'; return; }
      const totalAwal = filtered.reduce((s,d)=>s+d.stokAwal,0);
      const totalMasuk = filtered.reduce((s,d)=>s+d.masuk,0);
      const totalKeluar = filtered.reduce((s,d)=>s+d.keluar,0);
      const totalAkhir = filtered.reduce((s,d)=>s+d.stokAkhir,0);
      const sbInputStyle = 'width:100%;max-width:78px;text-align:right;padding:4px 6px;border-radius:6px;border:1px solid var(--border);background:var(--surface);font-family:var(--mono);font-size:12px';
      let rows = filtered.map(d => `<tr data-date="${esc((d.date||'').substring(0,10))}" data-sku="${esc(d.sku||'')}" data-nama="${esc(d.nama||'')}">
        <td style="white-space:nowrap">${esc(d.date||'-')}</td>
        <td style="font-family:var(--mono);font-size:11px">${esc(d.sku||'-')}</td>
        <td>${esc(d.nama||'-')}</td>
        <td style="text-align:right"><input type="number" class="sb-edit-input sb-f-awal" value="${d.stokAwal}" style="${sbInputStyle}" onfocus="this.dataset.orig=this.value;this.select()" oninput="onSbCellInput(this)" onblur="onSbCellBlur(this)"></td>
        <td style="text-align:right"><input type="number" class="sb-edit-input sb-f-masuk" value="${d.masuk}" style="${sbInputStyle};color:var(--biru);font-weight:700" onfocus="this.dataset.orig=this.value;this.select()" oninput="onSbCellInput(this)" onblur="onSbCellBlur(this)"></td>
        <td style="text-align:right"><input type="number" class="sb-edit-input sb-f-keluar" value="${d.keluar}" style="${sbInputStyle};color:var(--merah)" onfocus="this.dataset.orig=this.value;this.select()" oninput="onSbCellInput(this)" onblur="onSbCellBlur(this)"></td>
        <td style="text-align:right"><input type="number" class="sb-edit-input sb-f-akhir" value="${d.stokAkhir}" style="${sbInputStyle};color:var(--hijau,#16a34a);font-weight:800" onfocus="this.dataset.orig=this.value;this.select()" oninput="onSbAkhirInput(this)" onblur="onSbCellBlur(this)"></td>
      </tr>`).join('');
      el.innerHTML = `<div class="card">
        <div class="total-box" style="margin-bottom:12px">
          <div class="flex-between"><span>Total Stok Awal</span><span id="sbTotalAwal" style="font-family:var(--mono)">${totalAwal}</span></div>
          <div class="flex-between"><span>Total Masuk</span><span id="sbTotalMasuk" style="font-family:var(--mono);color:var(--biru);font-weight:700">${totalMasuk}</span></div>
          <div class="flex-between"><span>Total Keluar</span><span id="sbTotalKeluar" style="font-family:var(--mono);color:var(--merah)">${totalKeluar}</span></div>
          <div class="flex-between" style="font-size:1.1rem;font-weight:800"><span>Total Stok Akhir</span><span id="sbTotalAkhir" style="font-family:var(--mono);color:var(--hijau,#16a34a)">${totalAkhir}</span></div>
        </div>
        <p class="text-sm" style="color:var(--text3);margin:0 0 8px;font-size:0.7rem"><i class="fas fa-circle-info"></i> Klik sel Stok Awal/Masuk/Keluar/Stok Akhir untuk edit manual — otomatis tersimpan begitu pindah/klik di luar sel.</p>
        <div class="table-wrap"><table>
          <thead><tr><th>Tanggal</th><th>SKU</th><th>Nama</th><th>Stok Awal</th><th>Masuk</th><th>Keluar</th><th>Stok Akhir</th></tr></thead>
          <tbody>${rows}</tbody>
        </table></div>
      </div>`;
    }

    // ========== EDIT MANUAL STOCK BARANG (Stok Awal/Masuk/Keluar/Stok Akhir) ==========
    // Mengubah salah satu dari 4 kolom di tabel Stock Barang langsung dari sel tabel,
    // tersimpan otomatis ke Sheet MasterStock (fungsi updateStockRow di backend) begitu
    // sel kehilangan fokus (blur) atau pindah tab/enter.
    function onSbCellInput(inputEl) {
      // Auto-hitung ulang Stok Akhir dari Awal+Masuk-Keluar, KECUALI kalau Stok Akhir
      // baris ini sudah pernah diedit manual secara langsung (dataset.dirty) - dalam hal
      // itu Stok Akhir dianggap hasil stock-opname manual dan tidak ditimpa otomatis.
      const tr = inputEl.closest('tr');
      if (!tr) return;
      const akhirInput = tr.querySelector('.sb-f-akhir');
      if (akhirInput && akhirInput.dataset.dirty !== '1') {
        const awal = parseFloat(tr.querySelector('.sb-f-awal').value) || 0;
        const masuk = parseFloat(tr.querySelector('.sb-f-masuk').value) || 0;
        const keluar = parseFloat(tr.querySelector('.sb-f-keluar').value) || 0;
        akhirInput.value = awal + masuk - keluar;
      }
    }
    function onSbAkhirInput(inputEl) {
      inputEl.dataset.dirty = '1'; // tandai Stok Akhir sudah di-override manual oleh user
    }
    let _sbSaveTimers = {};
    function onSbCellBlur(inputEl) {
      // [BUGFIX] Sebelumnya fungsi ini SELALU menyimpan ke server tiap sel kehilangan
      // fokus, walau nilainya sama sekali TIDAK diubah (misal cuma tersentuh/ke-scroll
      // di HP, atau user cuma klik masuk lalu klik keluar tanpa mengetik apa-apa).
      // Karena Masuk/Keluar yang ditampilkan itu hasil KALKULASI ULANG otomatis dari
      // riwayat transaksi (bukan angka mentah dari Sheet), setiap blur yang tidak
      // sengaja itu diam-diam ikut MENULIS ULANG Sheet MasterStock dengan nilai hasil
      // kalkulasi saat itu - inilah yang menyebabkan data Stock/Rollover jadi kacau.
      // Sekarang: dibandingkan dulu ke nilai saat sel di-fokus (data-orig); kalau tidak
      // ada perubahan sama sekali, TIDAK ada apa pun yang dikirim ke server.
      if (inputEl.dataset.orig !== undefined && inputEl.dataset.orig === inputEl.value) return;
      const tr = inputEl.closest('tr');
      if (!tr) return;
      const date = tr.dataset.date, sku = tr.dataset.sku, nama = tr.dataset.nama;
      const stokAwal = parseFloat(tr.querySelector('.sb-f-awal').value) || 0;
      const masuk = parseFloat(tr.querySelector('.sb-f-masuk').value) || 0;
      const keluar = parseFloat(tr.querySelector('.sb-f-keluar').value) || 0;
      const stokAkhir = parseFloat(tr.querySelector('.sb-f-akhir').value) || 0;
      const key = date + '|' + sku;
      clearTimeout(_sbSaveTimers[key]);
      // Debounce singkat: kalau user Tab cepat antar sel di baris yang sama, cukup 1x simpan.
      _sbSaveTimers[key] = setTimeout(async () => {
        tr.style.transition = 'background .2s';
        tr.style.background = 'rgba(26,109,181,0.06)';
        try {
          await gasCall('updateStockRow', [{ date, sku, nama, stokAwal, masuk, keluar, stokAkhir }]);
          const idx = _stockBarangAll.findIndex(d => (d.date||'').substring(0,10) === date && d.sku === sku);
          if (idx >= 0) { _stockBarangAll[idx].stokAwal = stokAwal; _stockBarangAll[idx].masuk = masuk; _stockBarangAll[idx].keluar = keluar; _stockBarangAll[idx].stokAkhir = stokAkhir; }
          recalcSbTotalsFromDom();
          tr.style.background = 'rgba(22,163,74,0.12)';
          setTimeout(() => { tr.style.background = ''; }, 500);
        } catch (e) {
          tr.style.background = 'rgba(239,68,68,0.12)';
          setTimeout(() => { tr.style.background = ''; }, 800);
          Swal.fire({ toast: true, position: 'top-end', showConfirmButton: false, timer: 2500, icon: 'error', title: 'Gagal simpan: ' + e.message });
        }
      }, 250);
    }
    function recalcSbTotalsFromDom() {
      const rows = document.querySelectorAll('#sbContent tbody tr');
      let totalAwal = 0, totalMasuk = 0, totalKeluar = 0, totalAkhir = 0;
      rows.forEach(tr => {
        totalAwal += parseFloat(tr.querySelector('.sb-f-awal')?.value) || 0;
        totalMasuk += parseFloat(tr.querySelector('.sb-f-masuk')?.value) || 0;
        totalKeluar += parseFloat(tr.querySelector('.sb-f-keluar')?.value) || 0;
        totalAkhir += parseFloat(tr.querySelector('.sb-f-akhir')?.value) || 0;
      });
      const setTxt = (id, v) => { const e = document.getElementById(id); if (e) e.textContent = v; };
      setTxt('sbTotalAwal', totalAwal);
      setTxt('sbTotalMasuk', totalMasuk);
      setTxt('sbTotalKeluar', totalKeluar);
      setTxt('sbTotalAkhir', totalAkhir);
    }
    // [NEW] Selama ini fungsi GAS 'saveMasterStock' tidak pernah dipanggil dari web, jadi data Masuk/
    // Keluar/Stok Akhir di Sheet MasterStock tidak pernah ikut ter-update walau web sudah menghitung
    // dengan benar (web mengoreksi "Masuk" memakai stockInHistory, filter status 'kiriman' saja,
    // 'titipan' tidak dihitung sebagai stok masuk). Fungsi ini mengirim ulang data versi web (yang
    // sudah benar) ke Sheets, dikelompokkan per tanggal sesuai format yang diminta saveMasterStock.
    // Tidak mengubah logic koreksi kiriman/titipan yang sudah ada di doStockBarang().
    async function syncStockBarangToSheet() {
      if (!_stockBarangAll || !_stockBarangAll.length) return Swal.fire('Info','Belum ada data Stock Barang yang dimuat.','info');
      // [FIX] Sama seperti doStockBarang(): keluar harus dihitung dari transaksi penjualan (allTrxList),
      // bukan dipakai mentah dari d.keluar (yang selalu 0 di Sheets), supaya yang disinkronkan ke
      // Sheets juga benar, bukan ikut menimpa dengan 0.
      const tanggalRelevan = [...new Set(_stockBarangAll.map(d => (d.date||'').substring(0,10)).filter(Boolean))];
      await ensureTrxItemsForDates(tanggalRelevan);
      const keluarMap = buildKeluarMapFromTrx(tanggalRelevan);
      const corrected = _stockBarangAll.map(d => {
        const recordsForDate = stockInHistory.filter(s => (s.date||s.tgl||'').substring(0,10) === (d.date||'').substring(0,10) && s.sku === d.sku);
        const localMasuk = recordsForDate.filter(s => (s.status||'').toLowerCase() === 'kiriman').reduce((sum, s) => sum + (s.qty||0), 0);
        const masuk = recordsForDate.length > 0 ? localMasuk : (d.masuk||0);
        const keluar = keluarMap.get((d.date||'').substring(0,10) + '|' + d.sku) || 0;
        return { ...d, masuk, keluar, stokAkhir: (d.stokAwal||0) + masuk - keluar };
      });
      const byDate = {};
      corrected.forEach(d => { const tgl = (d.date||'').substring(0,10); if (!tgl) return; if (!byDate[tgl]) byDate[tgl] = []; byDate[tgl].push(d); });
      const dates = Object.keys(byDate);
      if (!dates.length) return Swal.fire('Info','Tidak ada data dengan tanggal valid untuk disinkronkan.','info');
      Swal.fire({ title:'Menyinkronkan...', html:'Mengirim data ke Google Sheets, mohon tunggu.', allowOutsideClick:false, didOpen:()=>Swal.showLoading() });
      let okCount = 0, failCount = 0, errMsgs = [];
      for (const tgl of dates) {
        try {
          await gasUploadFoto('saveMasterStock', [{ date: tgl, stock: byDate[tgl] }]);
          okCount++;
        } catch(e) {
          failCount++;
          errMsgs.push(tgl + ': ' + e.message);
          console.warn('Gagal sync MasterStock tanggal '+tgl+':', e);
        }
      }
      Swal.fire({ icon: failCount ? 'warning' : 'success', title: failCount ? 'Sebagian gagal' : 'Sinkronisasi berhasil', html: `${okCount} tanggal berhasil${failCount ? ', ' + failCount + ' tanggal gagal' : ''}.${errMsgs.length ? '<div style="margin-top:10px;text-align:left;font-size:11px;color:#DC2626;background:#FEF2F2;padding:8px;border-radius:8px;max-height:150px;overflow-y:auto">'+errMsgs.map(esc).join('<br>')+'</div>' : ''}` });
      loadStockBarang();
    }

    async function rolloverStokAwal() {
      const today = localDateStr();
      // Hitung kemarin (lokal)
      const _kemarin = new Date(); _kemarin.setDate(_kemarin.getDate() - 1);
      const kemarin = localDateStr(_kemarin);

      // Cek apakah data hari ini sudah ada di GAS
      const dataHariIni = _stockBarangAll.filter(d => (d.date||'').substring(0,10) === today);
      if (dataHariIni.length > 0) {
        const konfirm = await Swal.fire({ title: 'Data hari ini sudah ada', text: `Stock tanggal ${today} sudah ada (${dataHariIni.length} SKU). Tetap lakukan rollover dan timpa stok awal hari ini?`, icon: 'warning', showCancelButton: true, confirmButtonText: 'Ya, timpa', cancelButtonText: 'Batal' });
        if (!konfirm.isConfirmed) return;
      }

      // Ambil data kemarin dari _stockBarangAll
      const dataKemarin = _stockBarangAll.filter(d => (d.date||'').substring(0,10) === kemarin);
      if (!dataKemarin.length) {
        return Swal.fire('Tidak ada data', `Tidak ada data stock untuk tanggal kemarin (${kemarin}). Pastikan data kemarin sudah ada di sistem.`, 'warning');
      }

      // Hitung stok akhir kemarin (dengan koreksi dari stockInHistory lokal)
      // [FIX] Sebelumnya pakai d.keluar||0 mentah dari Sheets (selalu 0, sama seperti bug di
      // doStockBarang() yang sudah diperbaiki). Sekarang pakai keluar dari transaksi penjualan
      // (allTrxList) lewat helper yang sama: ensureTrxItemsForDates() + buildKeluarMapFromTrx().
      await ensureTrxItemsForDates([kemarin]);
      const keluarMapKemarin = buildKeluarMapFromTrx([kemarin]);
      const rolloverData = dataKemarin.map(d => {
        const recordsForDate = stockInHistory.filter(s => (s.date||s.tgl||'').substring(0,10) === kemarin && s.sku === d.sku);
        const localMasuk = recordsForDate.filter(s => (s.status||'').toLowerCase() === 'kiriman').reduce((sum, s) => sum + (s.qty||0), 0);
        const masuk = recordsForDate.length > 0 ? localMasuk : (d.masuk||0);
        const keluarKemarin = keluarMapKemarin.get(kemarin + '|' + d.sku) || 0;
        const stokAkhirKemarin = (d.stokAwal||0) + masuk - keluarKemarin;
        return { date: today, sku: d.sku, nama: d.nama, stokAwal: stokAkhirKemarin, masuk: 0, keluar: 0 };
      });

      // Preview ke user
      const previewRows = rolloverData.map(r => `<tr><td style="font-family:var(--mono);font-size:11px">${esc(r.sku)}</td><td>${esc(r.nama)}</td><td style="text-align:right;font-weight:700;color:var(--biru)">${r.stokAwal}</td></tr>`).join('');
      const konfirmFinal = await Swal.fire({
        title: `🔄 Rollover Stok ke ${today}`,
        html: `<p style="font-size:13px;margin-bottom:10px">Stok akhir <b>${kemarin}</b> → Stok awal <b>${today}</b></p><div style="max-height:250px;overflow-y:auto"><table style="width:100%;font-size:12px;border-collapse:collapse"><thead><tr><th style="text-align:left;padding:4px 8px;background:#EAF4FD;color:#1A6DB5">SKU</th><th style="text-align:left;padding:4px 8px;background:#EAF4FD;color:#1A6DB5">Nama</th><th style="text-align:right;padding:4px 8px;background:#EAF4FD;color:#1A6DB5">Stok Awal Baru</th></tr></thead><tbody>${previewRows}</tbody></table></div>`,
        icon: 'question', showCancelButton: true, confirmButtonText: '✅ Simpan Rollover', cancelButtonText: 'Batal', width: '500px'
      });
      if (!konfirmFinal.isConfirmed) return;

      Swal.fire({ title: 'Menyimpan...', text: 'Mengirim data rollover ke server...', allowOutsideClick: false, didOpen: () => Swal.showLoading() });
      let berhasil = 0, gagal = 0;
      for (const r of rolloverData) {
        try {
          await gasCall('updateStockAwal', [r]);
          berhasil++;
        } catch(e) {
          console.warn('Gagal rollover SKU', r.sku, e);
          gagal++;
        }
      }
      Swal.close();
      if (berhasil > 0) {
        Swal.fire({ icon: gagal > 0 ? 'warning' : 'success', title: 'Rollover Selesai', text: `${berhasil} SKU berhasil${gagal > 0 ? ', '+gagal+' SKU gagal' : ''}.` });
        // Reload data stock
        try {
          const data = await gasCall('getStockBarang', []);
          if (Array.isArray(data)) { _stockBarangAll = data; doStockBarang(); }
        } catch(e) { console.warn('Gagal reload stock:', e); }
      } else {
        Swal.fire({ icon: 'error', title: 'Gagal', text: 'Semua SKU gagal di-rollover. Periksa fungsi updateStockAwal di GAS.' });
      }
    }

    // ================================================================
    // [NEW] AUTO ROLLOVER STOK — dijalankan otomatis setiap pukul 00:00,
    // memakai ulang logika perhitungan yang sama seperti tombol manual
    // "🔄 Rollover Stok" (rolloverStokAwal), tapi tanpa dialog konfirmasi
    // (berjalan diam-diam di background). Fungsi rolloverStokAwal() yang
    // sudah ada TIDAK diubah sama sekali.
    // ================================================================
    async function autoRolloverStokAwal() {
      try {
        const today = localDateStr();
        const _kemarin = new Date(); _kemarin.setDate(_kemarin.getDate() - 1);
        const kemarin = localDateStr(_kemarin);

        // Jangan timpa kalau stok hari ini sudah ada (mis. sudah pernah di-rollover)
        const dataHariIni = _stockBarangAll.filter(d => (d.date||'').substring(0,10) === today);
        if (dataHariIni.length > 0) { console.log('[AutoRollover] Stok hari ini sudah ada, dilewati.'); return; }

        const dataKemarin = _stockBarangAll.filter(d => (d.date||'').substring(0,10) === kemarin);
        if (!dataKemarin.length) { console.log('[AutoRollover] Tidak ada data stok kemarin, dilewati.'); return; }

        await ensureTrxItemsForDates([kemarin]);
        const keluarMapKemarin = buildKeluarMapFromTrx([kemarin]);
        const rolloverData = dataKemarin.map(d => {
          const recordsForDate = stockInHistory.filter(s => (s.date||s.tgl||'').substring(0,10) === kemarin && s.sku === d.sku);
          const localMasuk = recordsForDate.filter(s => (s.status||'').toLowerCase() === 'kiriman').reduce((sum, s) => sum + (s.qty||0), 0);
          const masuk = recordsForDate.length > 0 ? localMasuk : (d.masuk||0);
          const keluarKemarin = keluarMapKemarin.get(kemarin + '|' + d.sku) || 0;
          const stokAkhirKemarin = (d.stokAwal||0) + masuk - keluarKemarin;
          return { date: today, sku: d.sku, nama: d.nama, stokAwal: stokAkhirKemarin, masuk: 0, keluar: 0 };
        });

        let berhasil = 0, gagal = 0;
        for (const r of rolloverData) {
          try { await gasCall('updateStockAwal', [r]); berhasil++; }
          catch(e) { console.warn('[AutoRollover] Gagal rollover SKU', r.sku, e); gagal++; }
        }
        console.log(`[AutoRollover] Selesai: ${berhasil} berhasil, ${gagal} gagal.`);

        if (berhasil > 0) {
          try {
            const data = await gasCall('getStockBarang', []);
            if (Array.isArray(data)) { _stockBarangAll = data; if (currentPage === 'stockbarang') doStockBarang(); }
          } catch(e) { console.warn('[AutoRollover] Gagal reload stock:', e); }
          if (typeof Swal !== 'undefined') {
            Swal.fire({ toast:true, position:'top-end', showConfirmButton:false, timer:3000, icon: gagal>0?'warning':'success', title:`Rollover stok otomatis (${today}): ${berhasil} SKU${gagal>0?', '+gagal+' gagal':''}` });
          }
        }
      } catch(e) { console.warn('[AutoRollover] Error:', e); }
    }

    // Cek tiap 1 menit; jalankan tepat sekali saat jam menunjukkan 00:00 (per hari)
    function startAutoRolloverScheduler() {
      const checkAndRun = () => {
        const now = new Date();
        const todayStr = localDateStr();
        const lastRun = localStorage.getItem('tirtaLastAutoRollover');
        if (now.getHours() === 0 && now.getMinutes() === 0 && lastRun !== todayStr) {
          localStorage.setItem('tirtaLastAutoRollover', todayStr);
          autoRolloverStokAwal();
        }
      };
      checkAndRun();
      setInterval(checkAndRun, 60000);
    }

    function addItemInputRow(skuVal) { let pOpts = '<option value="">-- pilih --</option>'; products.forEach(p => { pOpts += `<option value="${esc(p.sku)}">${esc(p.sku)} - ${esc(p.nama)}</option>`; }); const div = document.createElement('div'); div.className = 'cart-item-row'; div.innerHTML = `<select class="cart-item-select" style="flex:2;min-width:100px" onchange="isiModalInputRow(this)">${pOpts}</select><input class="cart-qty" type="number" min="1" value="1" style="width:50px" oninput="recalcInputTotals()"><input class="cart-disc" type="number" min="0" value="0" placeholder="Harga Modal" readonly style="width:70px;background:var(--biru-muda)"><input class="cart-disc" type="number" min="0" value="" placeholder="Disc" style="width:55px" oninput="recalcInputTotals()"><button class="btn btn-danger btn-sm" onclick="this.parentElement.remove();recalcInputTotals()">✕</button>`; document.getElementById('inputItemsContainer').appendChild(div); if (skuVal) { const sel = div.querySelector('select'); sel.value = skuVal; isiModalInputRow(sel); } recalcInputTotals(); }
    function isiModalInputRow(sel) { const sku = sel.value; const p = products.find(x => x.sku === sku); const row = sel.closest('.cart-item-row'); if (!row) return; const inputs = row.querySelectorAll('input'); inputs[1].value = p ? (p.modal || 0) : 0; recalcInputTotals(); }
    function recalcInputTotals() { const rows = document.querySelectorAll('#inputItemsContainer .cart-item-row'); let tq=0,gm=0,td=0; rows.forEach(row => { const inputs = row.querySelectorAll('input'); const q = parseInt(inputs[0].value)||0, h = parseFloat(inputs[1].value)||0, d = parseFloat(inputs[2].value)||0; tq+=q; gm+=q*h; td+=q*d; }); document.getElementById('inpTotalQty').textContent=tq; document.getElementById('inpGrossModal').textContent=fmtRp(gm); document.getElementById('inpTotalDisc').textContent=fmtRp(td); document.getElementById('inpNetModal').textContent=fmtRp(gm-td); }
    function getInputItems() { const rows = document.querySelectorAll('#inputItemsContainer .cart-item-row'); const items = []; rows.forEach(row => { const sel = row.querySelector('select'); const inputs = row.querySelectorAll('input'); const sku = sel.value; const p = products.find(x => x.sku === sku); if (!sku || !p) return; const qty = parseInt(inputs[0].value)||0, hargaModal = parseFloat(inputs[1].value)||0, disc = parseFloat(inputs[2].value)||0; if (qty > 0) items.push({ sku, nama: p.nama, qty, hargaModal, disc, netModal: (hargaModal - disc) * qty }); }); return items; }
    async function saveStockIn() { 
      const inpId = document.getElementById('inpId').value.trim(), driver = document.getElementById('inpDriver').value, rit = document.getElementById('inpRit').value.trim(), status = document.getElementById('inpStatus').value; 
      if (stockInHistory.some(e => e.groupId === inpId)) return Swal.fire('Info', 'Input Barang dengan ID '+inpId+' sudah diinput!', 'info');
      if (!driver) return Swal.fire('Error','Driver wajib dipilih!','error');
      if (!rit) return Swal.fire('Error','Rit wajib diisi!','error');
      if (!status) return Swal.fire('Error','Status wajib dipilih!','error');
      const itemRows = document.querySelectorAll('#inputItemsContainer .cart-item-row');
      for (let row of itemRows) {
        const sel = row.querySelector('select');
        if (!sel || !sel.value) return Swal.fire('Error','Semua item harus dipilih produknya (SKU)!','error');
      }
      const items = getInputItems(); 
      if (!items.length) return Swal.fire('Error','Minimal satu item harus diisi','error'); 
      const now = new Date(), date = localDateStr(now), createdAt = localDateStr(now)+' '+String(now.getHours()).padStart(2,'0')+':'+String(now.getMinutes()).padStart(2,'0')+':'+String(now.getSeconds()).padStart(2,'0'); 
      const entries = items.map((it, idx) => ({ id: inpId + '-' + (idx+1), groupId: inpId, sku: it.sku, nama: it.nama, qty: it.qty, hargaModal: it.hargaModal, disc: it.disc, netModal: it.netModal, driver, rit, status, date, createdAt })); 
      entries.forEach(e => stockInHistory.unshift(e)); 
      saveLocalData(); 
      try { for (const e of entries) await gasCall('saveInputBarang', [e]); } catch(e) { console.warn('Gagal simpan ke GAS:', e); } 
      Swal.fire({ toast: true, position: 'top-end', showConfirmButton: false, timer: 1500, icon: 'success', title: 'Barang masuk dicatat' }); 
      addNotification('📦', 'Input Barang Baru: '+inpId, (driver||'-')+' · '+items.length+' item · '+fmtRp(items.reduce((s,it)=>s+it.netModal,0)));
      loadInputBarang(); syncMasterStockToSheet(); 
    }

    function renderStockHistory() {
      const el = document.getElementById('stkHistory');
      if (!el) return;
      if (!stockInHistory.length) { el.innerHTML = '<p class="text-sm text-center">Memuat data...</p>'; return; }
      let rows = stockInHistory.slice(0,50).map(s => {
        const disc = s.disc || 0;
        const netModal = (s.hargaModal - disc) * s.qty;
        return `<tr>
          <td style="font-family:var(--mono);font-size:10px">${esc(s.id||'')}</td>
          <td style="white-space:nowrap">${s.date || (s.createdAt ? (s.createdAt.length > 10 ? new Date(s.createdAt).toISOString().substring(0,10) : s.createdAt.substring(0,10)) : '-')}</td>
          <td style="font-family:var(--mono);font-size:11px">${esc(s.sku)}</td>
          <td>${esc(s.nama||'')}</td>
          <td><input type="number" min="1" value="${s.qty}" style="width:60px;padding:2px 4px;font-size:11px;border:1px solid var(--border);border-radius:6px" onchange="editStockQty('${esc(s.id).replace(/'/g,"\\'")}',this.value)"></td>
          <td>${fmtRp(disc)}</td>
          <td>${fmtRp(s.hargaModal)}</td>
          <td style="font-weight:700;color:var(--biru)">${fmtRp(netModal)}</td>
          <td>${esc(s.driver||'-')}</td>
          <td>${esc(s.rit||'-')}</td>
          <td><select style="font-size:0.65rem;padding:2px 4px;border:1px solid var(--border);border-radius:6px;background:var(--surface)" onchange="editStockStatus('${esc(s.id).replace(/'/g,"\\'")}',this.value)"><option value="kiriman" ${s.status==='kiriman'?'selected':''}>Kiriman</option><option value="titipan" ${s.status==='titipan'?'selected':''}>Titipan</option></select></td>
          <td><button class="btn btn-danger btn-sm" onclick="deleteStockIn('${esc(s.id).replace(/'/g,"\\'")}')">🗑</button></td>
        </tr>`;
      }).join('');
      el.innerHTML = `<div class="table-wrap"><table><thead><tr><th>ID</th><th>Tanggal</th><th>SKU</th><th>Nama</th><th>Qty</th><th>Disc</th><th>Harga Modal</th><th>Net Modal</th><th>Driver</th><th>Rit</th><th>Status</th><th>Aksi</th></tr></thead><tbody>${rows}</tbody></table></div>`;
    }
    
    function editStockQty(id, newQty) {
      const idx = stockInHistory.findIndex(s => s.id === id);
      if (idx >= 0) { stockInHistory[idx].qty = parseInt(newQty)||0; stockInHistory[idx].netModal = (stockInHistory[idx].hargaModal - (stockInHistory[idx].disc||0)) * stockInHistory[idx].qty; saveLocalData(); try { gasCall('updateInputBarang', [{ id, qty: parseInt(newQty)||0 }]); } catch(e) { console.warn('Gagal update qty di GAS:', e); } }
    }
    function editStockStatus(id, newStatus) {
      const idx = stockInHistory.findIndex(s => s.id === id);
      if (idx >= 0) { stockInHistory[idx].status = newStatus; saveLocalData(); try { gasCall('updateInputBarang', [{ id, status: newStatus }]); } catch(e) { console.warn('Gagal update status di GAS:', e); } Swal.fire({ toast:true, position:'top-end', showConfirmButton:false, timer:1500, icon:'success', title:'Status diperbarui' }); }
    }
    async function deleteStockIn(id) {
      const confirm = await Swal.fire({ title:'Hapus?', text:'Hapus data input barang '+id+'?', icon:'warning', showCancelButton:true });
      if (confirm.isConfirmed) {
        stockInHistory = stockInHistory.filter(s => s.id !== id);
        saveLocalData();
        try { await gasCall('deleteInputBarang', [id]); } catch(e) { console.warn('Gagal hapus di GAS:', e); }
        renderStockHistory();
        Swal.fire({ toast:true, position:'top-end', showConfirmButton:false, timer:1500, icon:'success', title:'Data dihapus' });
      }
    }
    async function syncStockHistoryFromGAS() { try { const data = await gasCall('getInputBarangHistory', []); if (Array.isArray(data) && data.length > 0) { stockInHistory = data; saveLocalData(); if (document.getElementById('stkHistory')) renderStockHistory(); } } catch(e) { console.warn('Gagal ambil riwayat input barang:', e); } }
    // [NEW] Sync riwayat setoran dari Google Sheets secara independen (tidak ikut Promise.all utama agar tidak mengganggu sync lain bila endpoint belum tersedia di backend)
    // [NEW] Normalisasi record setoran dari Google Sheets: kolom sheet memakai nama berbeda
    // (UangMak, Ekstra1Li, Ekstra1, Ekstra2Li, Ekstra2, CicilanHu, GrandTot, dst.) dari field internal aplikasi.
    // Fungsi ini mencocokkan beberapa kemungkinan nama kolom tanpa mengubah struktur data internal yang sudah berjalan.
    function normalizeSetoranRecord(raw) {
      if (!raw || typeof raw !== 'object') return raw;
      const g = (...keys) => { for (const k of keys) { if (raw[k] !== undefined && raw[k] !== null && raw[k] !== '') return raw[k]; } return undefined; };
      const num = v => parseFloat(v) || 0;
      return {
        tgl: g('tgl','Tanggal','tanggal') || '',
        sales: g('sales','Sales') || '',
        grandTotal: num(g('grandTotal','GrandTot','grandTot')),
        makan: num(g('makan','UangMak','UangMakan','uangMakan')),
        tips: num(g('tips','Tips')),
        parkir: num(g('parkir','Parkir')),
        bensin: num(g('bensin','Bensin')),
        flazz: num(g('flazz','Flazz')),
        transfer: num(g('transfer','Transfer')),
        cicilan: num(g('cicilan','CicilanHu','Cicilan')),
        tagihan: num(g('tagihan','Tagihan')),
        ket1: g('ket1','Ekstra1Li','Ekstra1Ket') || '',
        jml1: num(g('jml1','Ekstra1')),
        ket2: g('ket2','Ekstra2Li','Ekstra2Ket') || '',
        jml2: num(g('jml2','Ekstra2')),
        total: num(g('total','Total')),
        setor: num(g('setor','Setor')),
        selisih: num(g('selisih','Selisih'))
      };
    }
    async function syncSetoranHistoryFromGAS() { try { const data = await gasCall('getSetoranHistory', []); if (Array.isArray(data) && data.length > 0) { setoranHistory = data.map(normalizeSetoranRecord); saveLocalData(); } } catch(e) { console.warn('Gagal ambil riwayat setoran dari GAS:', e); } }

