    function saveGasUrl() {
      const v = document.getElementById('setGasUrl').value.trim();
      if (!v || !v.startsWith('https://')) return Swal.fire('Error','URL tidak valid!','error');
      localStorage.setItem('tirtaGasUrl', v);
      GAS_URL = v;
      Swal.fire({ toast:true, position:'top-end', showConfirmButton:false, timer:2000, icon:'success', title:'URL GAS disimpan!' });
    }

    function saveSpreadsheetId() {
      const v = document.getElementById('setSpreadsheetId').value.trim();
      if (!v) return Swal.fire('Error','Spreadsheet ID tidak boleh kosong!','error');
      localStorage.setItem('tirtaSpreadsheetId', v);
      Swal.fire({ toast:true, position:'top-end', showConfirmButton:false, timer:2000, icon:'success', title:'Spreadsheet ID disimpan!' });
    }

    async function testGasConnection() {
      Swal.fire({ title:'Testing...', text:'Menghubungi GAS server...', allowOutsideClick:false, didOpen:()=>Swal.showLoading() });
      try {
        await gasCall('getSettings', []);
        Swal.fire({ icon:'success', title:'Koneksi OK!', text:'GAS server berhasil dihubungi.' });
      } catch(e) {
        Swal.fire({ icon:'error', title:'Gagal!', text:e.message, footer:'URL: ' + getGasUrl() });
      }
    }

    function uploadLogo(e) { const f = e.target.files[0]; if (!f) return; const r = new FileReader(); r.onload = ev => { _logoUrl = ev.target.result; localStorage.setItem('tirtaLogo', _logoUrl); document.getElementById('logoImg').src = _logoUrl; if (document.getElementById('logoPrev')) document.getElementById('logoPrev').innerHTML = `<img src="${_logoUrl}" style="max-height:80px;max-width:100%;border-radius:8px"><div style="font-size:11px;color:var(--text3);margin-top:6px">Klik untuk ganti</div>`; saveLocalData(); Swal.fire({ toast:true, position:'top-end', showConfirmButton:false, timer:1500, icon:'success', title:'Logo diperbarui!' }); }; r.readAsDataURL(f); }
    function uploadQris(e) { const f = e.target.files[0]; if (!f) return; const r = new FileReader(); r.onload = ev => { _qrisUrl = ev.target.result; localStorage.setItem('sp_qris', _qrisUrl); settings.qris = _qrisUrl; if (document.getElementById('qrisPrev')) document.getElementById('qrisPrev').innerHTML = `<img src="${_qrisUrl}" style="max-height:130px;max-width:100%;border-radius:8px"><div style="font-size:11px;color:var(--text3);margin-top:6px">Klik untuk ganti</div>`; saveLocalData(); }; r.readAsDataURL(f); }
    function renderSalesTags() { const el = document.getElementById('salesTagList'); if (!el) return; const list = settings.salesList||[]; el.innerHTML = list.length ? list.map((s,i) => `<span class="tag">${esc(s)} <button class="tag-remove" onclick="removeSalesName(${i})">✕</button></span>`).join('') : '<span style="color:var(--text3);font-size:13px">Belum ada sales</span>'; }
    function addSalesName() { const v = document.getElementById('newSalesName').value.trim(); if (!v) return; if (!settings.salesList) settings.salesList = []; if (!settings.salesList.includes(v)) settings.salesList.push(v); document.getElementById('newSalesName').value = ''; renderSalesTags(); }
    function removeSalesName(i) { settings.salesList.splice(i,1); renderSalesTags(); }
    function renderDriverTags() { const el = document.getElementById('driverTagList'); if (!el) return; el.innerHTML = drivers.length ? drivers.map((d,i) => `<span class="tag">${esc(d)} <button class="tag-remove" onclick="removeDriver(${i})">✕</button></span>`).join('') : '<span style="color:var(--text3);font-size:13px">Belum ada driver</span>'; }
    function addDriverName() { const v = document.getElementById('newDriverName').value.trim(); if (!v) return; if (!drivers.includes(v)) { drivers.push(v); saveLocalData(); gasCall('saveDrivers', [drivers.map(String)]).catch(e => console.warn('Gagal sync driver:', e)); } document.getElementById('newDriverName').value = ''; renderDriverTags(); }
    function removeDriver(i) { drivers.splice(i,1); saveLocalData(); gasCall('saveDrivers', [drivers.map(String)]).catch(e => console.warn('Gagal sync driver:', e)); renderDriverTags(); }
    function renderUserList() { const el = document.getElementById('userList'); if (!el) return; el.innerHTML = allUsers.length ? allUsers.map((u,i) => `<div class="flex-between mb-1" style="padding:4px 0;border-bottom:1px solid var(--border)"><span><b>${esc(u.name)}</b> (${u.role})</span><button class="btn btn-sm btn-danger" onclick="deleteUser(${i})">🗑</button></div>`).join('') : '<p class="text-sm text-center">Belum ada user</p>'; }
    function addUser() { const name = document.getElementById('newUserName').value.trim(), role = document.getElementById('newUserRole').value, pass = document.getElementById('newUserPass').value.trim(); if (!name || !pass) return Swal.fire('Error','Nama dan password wajib diisi','error'); if (allUsers.find(u => u.name === name)) return Swal.fire('Error','Nama sudah ada','error'); allUsers.push({ name, role }); saveLocalData(); gasCall('saveUser', [{ name, role, password: pass }]).catch(e => console.warn('Gagal sync user ke GAS:', e)); document.getElementById('newUserName').value = ''; document.getElementById('newUserPass').value = ''; renderUserList(); Swal.fire({ toast: true, position: 'top-end', showConfirmButton: false, timer: 1500, icon: 'success', title: 'User ditambahkan' }); }
    function deleteUser(i) { Swal.fire({ title:'Hapus user?', text:'Hapus '+allUsers[i].name+'?', icon:'warning', showCancelButton:true }).then(r => { if (r.isConfirmed) { const deletedName = allUsers[i].name; allUsers.splice(i,1); saveLocalData(); renderUserList(); gasCall('deleteUser', [deletedName]).catch(e => console.warn('Gagal hapus user GAS:', e)); Swal.fire({ toast: true, position: 'top-end', showConfirmButton: false, timer: 1500, icon: 'success', title: 'User dihapus' }); } }); }
    function savePengaturan() { settings.namaToko = document.getElementById('setNamaToko').value.trim(); settings.tagline = document.getElementById('setTagline').value.trim(); settings.alamat = document.getElementById('setAlamat').value.trim(); settings.telepon = document.getElementById('setTelepon').value.trim(); settings.bottomLine = document.getElementById('setFooter').value.trim(); settings.bank1 = { nama: document.getElementById('setB1Nama').value.trim(), norek: document.getElementById('setB1Norek').value.trim(), penerima: document.getElementById('setB1Penerima').value.trim() }; settings.bank2 = { nama: document.getElementById('setB2Nama').value.trim(), norek: document.getElementById('setB2Norek').value.trim(), penerima: document.getElementById('setB2Penerima').value.trim() }; document.getElementById('headerAlamat').textContent = settings.alamat; saveLocalData(); gasCall('saveSettings', [{ storeName: settings.namaToko||settings.storeName, tagline: settings.tagline, address: settings.alamat||settings.address, phone: settings.telepon||settings.phone, footer: settings.bottomLine||settings.footer, salesList: settings.salesList||[], bank1: settings.bank1, bank2: settings.bank2 }]).catch(e => console.warn('Gagal sync settings:', e)); Swal.fire({ toast: true, position: 'top-end', showConfirmButton: false, timer: 1500, icon: 'success', title: 'Pengaturan disimpan' }); }
    function backupData() { saveLocalData(); const blob = new Blob([localStorage.getItem('tirtaFullData')], {type:'application/json'}); const a = document.createElement('a'); a.href = URL.createObjectURL(blob); a.download = 'tirta-backup-'+new Date().toISOString().slice(0,10)+'.json'; a.click(); }
    function restoreData() { Swal.fire({ title:'Restore Data', text:'Pilih file backup JSON', icon:'warning', showCancelButton:true }).then(r => { if (r.isConfirmed) { const input = document.createElement('input'); input.type='file'; input.accept='.json'; input.onchange = e => { const file = e.target.files[0]; if (!file) return; const reader = new FileReader(); reader.onload = ev => { try { const data = JSON.parse(ev.target.result); localStorage.setItem('tirtaFullData', JSON.stringify(data)); loadLocalData(); Swal.fire('Sukses','Data direstore! Refresh halaman.','success'); } catch(err) { Swal.fire('Error','File tidak valid','error'); } }; reader.readAsText(file); }; input.click(); } }); }

