    function uploadSalesLogo(e) { uploadLogo(e); }
    function uploadSalesQris(e) { uploadQris(e); }
    function addDriverUser() { const v = document.getElementById('newDriverUser').value.trim(); if (!v) return; if (!drivers.includes(v)) { drivers.push(v); saveLocalData(); gasCall('saveDrivers', [drivers.map(String)]).catch(e => console.warn('Gagal sync driver:', e)); renderDriverUserTags(); } document.getElementById('newDriverUser').value = ''; Swal.fire({ toast:true, position:'top-end', showConfirmButton:false, timer:1500, icon:'success', title:'Driver ditambahkan' }); }
    function renderDriverUserTags() { const el = document.getElementById('driverUserTagList'); if (!el) return; el.innerHTML = drivers.length ? drivers.map((d,i) => `<span class="tag">${esc(d)} <button class="tag-remove" onclick="removeDriverUser(${i})">✕</button></span>`).join('') : '<span style="color:var(--text3);font-size:13px">Belum ada driver</span>'; }
