    const DEFAULT_SHEET_ID = '12q8SwBtoww9Y9c6EZ46-SNa1q5TKIXnf9g_3wLbsNK4';
    const DEFAULT_LAPORAN_SHEET_ID = '1Uw3PJ7efRnt2E_ccu9-SvHYbmirx6ZWyHxEDrSSMVYs';

    function loadGoogleSheets() {
      document.getElementById('contentArea').innerHTML = `
        <div class="card">
          <div class="card-title"><i class="fas fa-table-cells"></i> Google Sheets</div>
          <div class="section-title">📄 Buka Spreadsheet</div>
          <div class="flex-row mt-2">
            <button class="btn btn-outline" style="flex:1" onclick="window.open('https://docs.google.com/spreadsheets/d/${DEFAULT_SHEET_ID}/edit','_blank')"><i class="fas fa-database"></i> Buka Google Sheets (Database)</button>
          </div>
          <div class="flex-row mt-2">
            <button class="btn btn-outline" style="flex:1" onclick="window.open('https://docs.google.com/spreadsheets/d/${DEFAULT_LAPORAN_SHEET_ID}/edit','_blank')"><i class="fas fa-chart-bar"></i> Buka Laporan Google Sheets</button>
          </div>
          <div class="section-title">🔄 Sinkronisasi</div>
          <div class="flex-row mt-2">
            <button class="btn btn-primary" style="flex:1" id="btnSyncToSheets" onclick="syncAllToGAS()"><i class="fas fa-cloud-upload-alt"></i> Sync ke Google Sheets</button>
          </div>
          <div class="flex-row mt-2">
            <button class="btn btn-warning" style="flex:1" id="btnSyncToApp" onclick="syncAppFromGAS()"><i class="fas fa-cloud-download-alt"></i> Sync ke Aplikasi</button>
          </div>
          <div class="text-sm mt-2" style="color:var(--text3)">"Sync ke Google Sheets" mengirim data lokal (produk, transaksi, input barang, setoran, driver, pengaturan) ke Spreadsheet. "Sync ke Aplikasi" mengambil data terbaru dari Spreadsheet ke aplikasi ini.</div>
        </div>`;
    }

    async function syncAllToGAS() {
      const btn = document.getElementById('btnSyncToSheets');
      if (btn) { btn.disabled = true; btn.innerHTML = '<i class="fas fa-spinner fa-spin"></i> Menyinkronkan...'; }
      try {
        await syncProductsToSheet();
        await gasCall('saveSettings', [{ storeName: settings.namaToko||settings.storeName, tagline: settings.tagline, address: settings.alamat||settings.address, phone: settings.telepon||settings.phone, footer: settings.bottomLine||settings.footer, salesList: settings.salesList||[], bank1: settings.bank1, bank2: settings.bank2 }]).catch(e => console.warn('Gagal sync settings:', e));
        await gasCall('saveDrivers', [drivers.map(String)]).catch(e => console.warn('Gagal sync driver:', e));
        for (const t of allTrxList) { try { await gasCall('saveTrx', [t]); } catch(e) { console.warn('Gagal sync trx ke Sheets:', t.id, e); } }
        for (const s of stockInHistory) { try { await gasCall('saveInputBarang', [s]); } catch(e) { console.warn('Gagal sync input barang ke Sheets:', s.id, e); } }
        for (const s of setoranHistory) { try { await gasCall('saveSetoran', [s]); } catch(e) { console.warn('Gagal sync setoran ke Sheets:', e); } }
        Swal.fire({ toast: true, position: 'top-end', showConfirmButton: false, timer: 2000, icon: 'success', title: 'Sync ke Google Sheets selesai' });
      } catch(e) {
        Swal.fire({ icon:'error', title:'Gagal Sync', text: e.message });
      } finally {
        if (btn) { btn.disabled = false; btn.innerHTML = '<i class="fas fa-cloud-upload-alt"></i> Sync ke Google Sheets'; }
      }
    }

    async function syncAppFromGAS() {
      const btn = document.getElementById('btnSyncToApp');
      if (btn) { btn.disabled = true; btn.innerHTML = '<i class="fas fa-spinner fa-spin"></i> Menyinkronkan...'; }
      try {
        await syncFromGAS();
        await syncStockHistoryFromGAS();
        await syncSetoranHistoryFromGAS();
        Swal.fire({ toast: true, position: 'top-end', showConfirmButton: false, timer: 2000, icon: 'success', title: 'Sync ke Aplikasi selesai' });
      } catch(e) {
        Swal.fire({ icon:'error', title:'Gagal Sync', text: e.message });
      } finally {
        if (btn) { btn.disabled = false; btn.innerHTML = '<i class="fas fa-cloud-download-alt"></i> Sync ke Aplikasi'; }
      }
    }

    // ========== HELPERS ==========
    function fmtRp(n) { return 'Rp\u00a0' + Number(n||0).toLocaleString('id-ID'); }
    function fmtDate(s) { if (!s) return '-'; const p = String(s).substring(0,10).split('-'); if (p.length<3) return s; const m=['','Jan','Feb','Mar','Apr','Mei','Jun','Jul','Ags','Sep','Okt','Nov','Des']; return p[2]+' '+m[parseInt(p[1])]+' '+p[0]; }
    function genId() { const d = new Date(), pp = n => String(n).padStart(2,'0'); return 'TRX-'+d.getFullYear()+pp(d.getMonth()+1)+pp(d.getDate())+'-'+Math.random().toString(36).slice(2,6).toUpperCase(); }
    function esc(s) { return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }
    function localDateStr(d) { const dt = d||new Date(); return dt.getFullYear()+'-'+String(dt.getMonth()+1).padStart(2,'0')+'-'+String(dt.getDate()).padStart(2,'0'); }

    // PWA
    let deferredPrompt;
    window.addEventListener('beforeinstallprompt', e => { e.preventDefault(); deferredPrompt = e; document.getElementById('installBtn').style.display = 'block'; });
    function installApp() { if (deferredPrompt) { deferredPrompt.prompt(); deferredPrompt.userChoice.then(r => { if (r.outcome === 'accepted') console.log('Installed'); deferredPrompt = null; document.getElementById('installBtn').style.display = 'none'; }); } else { Swal.fire('Info','Klik menu browser > Add to Home Screen','info'); } }
    // Service Worker diaktifkan kembali agar memenuhi syarat installability PWA (Add to Home Screen)
if ('serviceWorker' in navigator) {
  navigator.serviceWorker.register('sw.js')
    .then(function(registration) {
      console.log('SW registered');
    })
    .catch(function(error) {
      console.log('SW registration failed', error);
    });
}
    // Inisialisasi URL default jika kosong
    if (!localStorage.getItem('tirtaGasUrl')) {
      localStorage.setItem('tirtaGasUrl', DEFAULT_GAS_URL);
    }
    loadLocalData();
    if (!allUsers || allUsers.length === 0) {
      allUsers = [
        { name:'admin', role:'admin' },
        { name:'hasan', role:'sales' },
        { name:'ujang', role:'sales' },
        { name:'oji', role:'driver' },
        { name:'padong', role:'driver' },
        { name:'said', role:'driver' },
        { name:'dedi', role:'driver' },
        { name:'tirta', role:'admin' }
      ];
      saveLocalData();
    }
    const savedUser = localStorage.getItem('tirtaUser');
    if (savedUser) { try { const parsed = JSON.parse(savedUser); sessionToken = parsed.token || null; currentUser = { name: parsed.name, role: parsed.role };
      if (localStorage.getItem('tirtaBioEnabled') === '1' && isBiometricSupported()) { showBioLockScreen(); } else { showMainApp(); }
    } catch(e) { localStorage.removeItem('tirtaUser'); } }
  

  // ============================================================
  // ADDITIF — PATCH ANTI DUPLIKAT ID (Menu Jual & Input Barang)
  // Tidak mengubah/menghapus fungsi, variabel, atau logika asli.
  // Hanya menambah lapisan pengaman di LUAR kode asli (wrapper),
  // supaya ID yang sama tidak bisa tersimpan lebih dari 1x —
  // termasuk kasus double-click/double-tap dan duplikat yang
  // lolos dari proses sinkron Google Sheets.
  // ============================================================
  (function() {
    // 1) Kunci sementara (busy-lock) supaya submitTrx & saveStockIn
    //    tidak bisa dieksekusi dobel akibat tombol Simpan ditekan 2x
    //    dengan sangat cepat (double-click / double-tap).
    if (typeof submitTrx === 'function') {
      var _origSubmitTrx = submitTrx;
      var _trxBusy = false;
      submitTrx = async function() {
        if (_trxBusy) return;
        _trxBusy = true;
        try { return await _origSubmitTrx.apply(this, arguments); }
        finally { _trxBusy = false; }
      };
    }
    if (typeof saveStockIn === 'function') {
      var _origSaveStockIn = saveStockIn;
      var _stockBusy = false;
      saveStockIn = async function() {
        if (_stockBusy) return;
        _stockBusy = true;
        try { return await _origSaveStockIn.apply(this, arguments); }
        finally { _stockBusy = false; }
      };
    }

    // 2) Saring (dedupe) data dengan ID yang sama setiap kali sebelum
    //    disimpan ke localStorage — jaga-jaga jika duplikat muncul
    //    dari proses sinkron Google Sheets (syncFromGAS) atau sumber lain,
    //    supaya tidak pernah ada 2 baris dengan ID sama yang tersimpan/tertampil.
    if (typeof saveLocalData === 'function') {
      var _origSaveLocalData = saveLocalData;
      saveLocalData = function() {
        try {
          if (Array.isArray(allTrxList)) {
            var seenTrx = new Set();
            allTrxList = allTrxList.filter(function(t) {
              if (!t || seenTrx.has(t.id)) return false;
              seenTrx.add(t.id);
              return true;
            });
          }
          if (Array.isArray(stockInHistory)) {
            var seenStock = new Set();
            stockInHistory = stockInHistory.filter(function(e) {
              if (!e || seenStock.has(e.id)) return false;
              seenStock.add(e.id);
              return true;
            });
          }
        } catch (err) { console.warn('Gagal menyaring data duplikat:', err); }
        return _origSaveLocalData.apply(this, arguments);
      };
    }
  })();
  

  // ============================================================
  // ADDITIF — FIX LOGO HILANG SAAT DOWNLOAD PNG (Struk Jual & Input Barang)
  // Tidak mengubah/menghapus fungsi, variabel, atau logika asli sedikit pun.
  //
  // Akar masalah: buildStrukHTML() & buildStrukInputBarangHTML() memakai
  // logo dari URL remote (_logoUrl) langsung. Saat PREVIEW (<img> biasa)
  // gambar lintas-domain tampil normal, tapi saat DOWNLOAD PNG (html2canvas
  // melukis ke <canvas>) gambar lintas-domain tanpa izin CORS gagal
  // dirender sehingga logo hilang dari hasil PNG — walau proses download
  // tetap "berhasil" (tidak error).
  //
  // Solusi: memakai teknik yang SUDAH ADA & terbukti berhasil di struk
  // Setoran (_ensureLogoDataUrl — mengubah logo jadi data URL base64
  // lebih dulu). Di sini kita terapkan pola yang sama untuk struk Jual
  // & Input Barang, dengan cara MEMBUNGKUS (wrap) buildStrukHTML dan
  // buildStrukInputBarangHTML dari LUAR, tanpa menyentuh isi fungsi asli.
  // ============================================================
  (function() {
    var _logoPngCache = null; // {src, data} — cache data URL logo, diisi otomatis di background

    function _refreshLogoPngCacheForDownload() {
      if (typeof _ensureLogoDataUrl !== 'function' || typeof _logoUrl === 'undefined' || !_logoUrl) return;
      if (_logoPngCache && _logoPngCache.src === _logoUrl) return; // sudah ter-cache & masih sama, tak perlu fetch ulang
      _ensureLogoDataUrl(_logoUrl).then(function(dataUrl) {
        _logoPngCache = { src: _logoUrl, data: dataUrl };
      });
    }
    _refreshLogoPngCacheForDownload();
    setInterval(_refreshLogoPngCacheForDownload, 4000); // jaga-jaga kalau logo diganti (upload logo baru / sinkron settings)

    if (typeof buildStrukHTML === 'function') {
      var _origBuildStrukHTML = buildStrukHTML;
      buildStrukHTML = function() {
        var _origLogo = _logoUrl;
        if (_logoPngCache && _logoPngCache.src === _logoUrl) _logoUrl = _logoPngCache.data;
        try { return _origBuildStrukHTML.apply(this, arguments); }
        finally { _logoUrl = _origLogo; }
      };
    }

    if (typeof buildStrukInputBarangHTML === 'function') {
      var _origBuildStrukInputBarangHTML = buildStrukInputBarangHTML;
      buildStrukInputBarangHTML = function() {
        var _origLogo = _logoUrl;
        if (_logoPngCache && _logoPngCache.src === _logoUrl) _logoUrl = _logoPngCache.data;
        try { return _origBuildStrukInputBarangHTML.apply(this, arguments); }
        finally { _logoUrl = _origLogo; }
      };
    }
  })();
  

  // ============================================================
  // ADDITIF — LOGO EMBEDDED (base64, tanpa dependensi ke server luar)
  // Tidak mengubah/menghapus fungsi, variabel, atau konstanta asli
  // (EMBEDDED_LOGO tetap seperti semula). Blok ini hanya MENIMPA nilai
  // runtime dari variabel _logoUrl (yang memang sudah "let", boleh
  // diubah) dari URL remote image2url.com (yang tidak CORS-friendly,
  // menyebabkan logo hilang saat Download PNG) menjadi data URI
  // (base64 WebP transparan) yang tertanam langsung di kode ini.
  //
  // Berlaku HANYA jika user belum upload logo custom sendiri lewat
  // menu Pengaturan (localStorage 'tirtaLogo' kosong) — logo custom
  // tetap diprioritaskan seperti perilaku asli aplikasi.
  //
  // Dijalankan berkala (self-healing) supaya tetap benar walau ada
  // proses lain (sync setting, dsb.) yang me-reset _logoUrl balik
  // ke EMBEDDED_LOGO bawaan.
  // ============================================================
  (function() {
    var _fixedLogoDataUri = "data:image/webp;base64,";

    function _healLogoUrl() {
      try {
        if (typeof _logoUrl === 'undefined') return;
        var hasCustomLogo = !!localStorage.getItem('tirtaLogo');
        if (hasCustomLogo) return; // hormati logo custom upload user, tidak diganggu
        if (typeof EMBEDDED_LOGO !== 'undefined' && _logoUrl === EMBEDDED_LOGO) {
          _logoUrl = _fixedLogoDataUri;
        }
      } catch (err) { /* diamkan, tidak boleh mengganggu aplikasi utama */ }
    }
    _healLogoUrl();
    setInterval(_healLogoUrl, 3000);
  })();
  

  // ============================================================
  // ADDITIF — PERCEPAT DOWNLOAD PNG (Struk Jual, Input Barang, Setoran)
  // Tidak mengubah/menghapus fungsi, variabel, atau logika asli.
  // doStrukPng / doInputBarangPng / doSetoranPng asli TETAP ADA di kode,
  // hanya "ditimpa" (override) dari luar dengan versi yang identik
  // perilakunya, TAPI mengganti jeda buatan tetap (setTimeout 400ms)
  // dengan deteksi otomatis "gambar sudah selesai dimuat" (event-driven),
  // dengan jaring pengaman maksimal 300ms kalau ada gambar yang lambat.
  // Hasil akhir (nama file, kualitas, toast, dsb.) 100% sama seperti asli.
  // ============================================================
  (function() {
    function _waitImagesReady(el, maxWaitMs) {
      var imgs = Array.prototype.slice.call(el.querySelectorAll('img'));
      if (imgs.length === 0) return Promise.resolve();
      var perImagePromises = imgs.map(function(img) {
        if (img.complete && img.naturalWidth > 0) {
          return (img.decode ? img.decode().catch(function(){}) : Promise.resolve());
        }
        return new Promise(function(res) {
          img.addEventListener('load', res, { once: true });
          img.addEventListener('error', res, { once: true });
        });
      });
      var safetyTimeout = new Promise(function(res) { setTimeout(res, maxWaitMs); });
      return Promise.race([Promise.all(perImagePromises), safetyTimeout]);
    }

    if (typeof doStrukPng === 'function') {
      doStrukPng = function() {
        if (!_strKData) return;
        var off = document.getElementById('strukOffscreen');
        off.style.cssText = 'position:fixed;left:-9999px;top:0;pointer-events:none;z-index:-1;background:#e8f2f9;padding:20px';
        var ns = (_strKData.trx.status || '').toLowerCase();
        var render = function() {
          off.innerHTML = buildStrukHTML(_strKData);
          var el = off.querySelector('#struk-root');
          if (!el) return Swal.fire('Error', 'Gagal render', 'error');
          _waitImagesReady(el, 300).then(function() {
            html2canvas(el, { backgroundColor: '#e8f2f9', scale: 2.5, useCORS: true, allowTaint: true, logging: false }).then(function(canvas) {
              var a = document.createElement('a');
              a.download = 'Struk-' + (_strKData.trx.id || 'trx') + '.png';
              a.href = canvas.toDataURL('image/png');
              document.body.appendChild(a); a.click(); document.body.removeChild(a);
              off.innerHTML = '';
              Swal.fire({ toast: true, position: 'top-end', showConfirmButton: false, timer: 2000, icon: 'success', title: 'Struk tersimpan' });
            }).catch(function(err) { off.innerHTML = ''; Swal.fire('Error', err.message, 'error'); });
          });
        };
        if (ns === 'qris' && _qrisUrl && _qrisUrl.indexOf('data:') !== 0) {
          _ensureQrisDataUrl(_qrisUrl).then(function(dataUrl) {
            var orig = _qrisUrl; _qrisUrl = dataUrl; render(); _qrisUrl = orig;
          });
        } else {
          render();
        }
      };
    }

    if (typeof doInputBarangPng === 'function') {
      doInputBarangPng = function() {
        if (!_lastInputBarangStruk) return;
        var off = document.getElementById('strukOffscreen');
        off.style.cssText = 'position:fixed;left:-9999px;top:0;pointer-events:none;z-index:-1;background:#e8f2f9;padding:20px';
        off.innerHTML = buildStrukInputBarangHTML(_lastInputBarangStruk);
        var el = off.querySelector('#inputbarang-root');
        if (!el) return Swal.fire('Error', 'Gagal render', 'error');
        _waitImagesReady(el, 300).then(function() {
          html2canvas(el, { backgroundColor: '#e8f2f9', scale: 2.5, useCORS: true, allowTaint: true, logging: false }).then(function(canvas) {
            var a = document.createElement('a');
            a.download = 'InputBarang-' + (_lastInputBarangStruk.id || 'item') + '.png';
            a.href = canvas.toDataURL('image/png');
            document.body.appendChild(a); a.click(); document.body.removeChild(a);
            off.innerHTML = '';
            Swal.fire({ toast: true, position: 'top-end', showConfirmButton: false, timer: 2000, icon: 'success', title: 'Struk tersimpan' });
          }).catch(function(err) { off.innerHTML = ''; Swal.fire('Error', err.message, 'error'); });
        });
      };
    }

    if (typeof doSetoranPng === 'function') {
      doSetoranPng = function() {
        if (!_lastSetoranPayload) return;
        var off = document.getElementById('strukOffscreen');
        off.style.cssText = 'position:fixed;left:-9999px;top:0;pointer-events:none;z-index:-1;background:#e8f2f9;padding:20px';
        _ensureLogoDataUrl(_logoUrl).then(function(logoData) {
          off.innerHTML = buildSetoranStrukHTML(_lastSetoranPayload, logoData);
          var el = off.querySelector('#setoran-root');
          if (!el) return Swal.fire('Error', 'Gagal render', 'error');
          _waitImagesReady(el, 300).then(function() {
            html2canvas(el, { backgroundColor: '#e8f2f9', scale: 2.5, useCORS: true, allowTaint: true, logging: false }).then(function(canvas) {
              var a = document.createElement('a');
              a.download = 'Setoran-' + (_lastSetoranPayload.sales) + '-' + (_lastSetoranPayload.tgl) + '.png';
              a.href = canvas.toDataURL('image/png');
              document.body.appendChild(a); a.click(); document.body.removeChild(a);
              off.innerHTML = '';
              Swal.fire({ toast: true, position: 'top-end', showConfirmButton: false, timer: 2000, icon: 'success', title: 'Struk setoran tersimpan' });
            }).catch(function(err) { off.innerHTML = ''; Swal.fire('Error', err.message, 'error'); });
          });
        });
      };
    }
  })();
  

  // ============================================================
  // ADDITIF — PERBAIKI "CETAK ULANG" TERASA LAMBAT/BERHENTI (Menu Transaksi)
  // Tidak mengubah/menghapus fungsi, variabel, atau logika asli.
  // cetakUlangStruk asli TETAP ADA di kode, hanya ditimpa (override)
  // dari luar dengan versi yang perilaku akhirnya identik, TAPI:
  //   1) Menampilkan indikator loading saat mengambil detail transaksi
  //      dari server, supaya tidak terlihat seperti "hang/berhenti".
  //   2) Menambah batas tunggu tampilan (UX timeout) 10 detik — kalau
  //      server lambat, struk tetap dibuka (memakai data yang ada)
  //      alih-alih membuat user menunggu sampai 40 detik tanpa kejelasan.
  //      Proses pengambilan data di background TETAP jalan; begitu
  //      selesai, hasilnya tetap disimpan untuk pemakaian berikutnya
  //      (klik "Cetak" kedua kali untuk transaksi yang sama jadi instan).
  // gasCall & mekanisme retry/timeout aslinya TIDAK disentuh sama sekali.
  // ============================================================
  (function() {
    if (typeof cetakUlangStruk !== 'function') return;

    cetakUlangStruk = async function(id) {
      let trx = allTrxList.find(function(t) { return t.id === id; });
      if (!trx) return Swal.fire('Error', 'Transaksi tidak ditemukan', 'error');

      if (!trx.items || trx.items.length === 0) {
        Swal.fire({
          title: 'Menyiapkan struk...',
          text: 'Mengambil detail transaksi dari server',
          allowOutsideClick: false,
          allowEscapeKey: false,
          didOpen: function() { Swal.showLoading(); }
        });

        var detailPromise = gasCall('getTrxDetail', [id]).then(function(detail) {
          if (detail && Array.isArray(detail.items) && detail.items.length > 0) {
            trx.items = detail.items;
            var idx = allTrxList.findIndex(function(t) { return t.id === id; });
            if (idx >= 0) allTrxList[idx] = Object.assign({}, allTrxList[idx], { items: detail.items });
            saveLocalData();
          }
          return detail;
        }).catch(function(e) { console.warn('Gagal ambil detail dari GAS:', e); return null; });

        var uxTimeoutPromise = new Promise(function(res) { setTimeout(function() { res('__ux_timeout__'); }, 10000); });

        try { await Promise.race([detailPromise, uxTimeoutPromise]); }
        catch (e) { console.warn('Gagal ambil detail dari GAS:', e); }

        Swal.close();
      }

      _strKData = { trx: trx, items: trx.items || [] };
      showStrukModal();
    };
  })();
  

  // ============================================================
  // ADDITIF — RESPONSIVITAS UMUM (1) Debounce pencarian Transaksi
  //                              (2) Coalesce/gabung penulisan saveLocalData
  // Tidak mengubah/menghapus fungsi, variabel, atau logika asli.
  // ============================================================
  (function() {
    // ---- (1) Debounce input pencarian di menu Transaksi ----
    // loadTransaksi() asli TETAP dipanggil apa adanya (tidak diubah).
    // Setelah itu, kita ganti handler bawaan oninput="filterTrx()" pada
    // input #trxSearch (yang tadinya trigger di SETIAP huruf) dengan
    // versi ber-debounce, supaya render tabel hanya jalan setelah user
    // berhenti mengetik sejenak (~300ms). Dropdown filter status/sales
    // TIDAK didebounce (tetap instan seperti asli), karena itu tidak
    // dipicu per-huruf.
    if (typeof loadTransaksi === 'function') {
      var _origLoadTransaksi = loadTransaksi;
      loadTransaksi = function() {
        var result = _origLoadTransaksi.apply(this, arguments);
        var searchEl = document.getElementById('trxSearch');
        if (searchEl && typeof filterTrx === 'function') {
          searchEl.oninput = null; // lepas handler bawaan yang tanpa debounce
          var _debounceTimer = null;
          searchEl.addEventListener('input', function() {
            if (_debounceTimer) clearTimeout(_debounceTimer);
            _debounceTimer = setTimeout(function() { filterTrx(); }, 300);
          });
        }
        return result;
      };
    }

    // ---- (2) Coalesce penulisan saveLocalData ----
    // saveLocalData asli TETAP ADA & TETAP dipanggil dengan isi yang sama
    // persis (tidak ada data yang diubah/dihilangkan). Yang berubah HANYA
    // waktu eksekusinya: kalau saveLocalData dipanggil berkali-kali dalam
    // waktu sangat berdekatan (<150ms), yang benar-benar menulis ke
    // localStorage cukup panggilan TERAKHIR saja — karena state yang
    // ditulis toh sama-sama mengambil data TERBARU dari variabel global
    // saat itu dijalankan (bukan snapshot lama), jadi hasil akhirnya identik
    // dengan kalau dipanggil berkali-kali, cuma lebih hemat proses tulis.
    if (typeof saveLocalData === 'function') {
      var _origSaveLocalData2 = saveLocalData;
      var _saveDebounceTimer = null;
      saveLocalData = function() {
        var args = arguments;
        var self = this;
        if (_saveDebounceTimer) clearTimeout(_saveDebounceTimer);
        _saveDebounceTimer = setTimeout(function() {
          _saveDebounceTimer = null;
          _origSaveLocalData2.apply(self, args);
        }, 150);
      };
      // Jaring pengaman: kalau tab ditutup/direfresh SAAT masih ada
      // penulisan yang tertunda (dalam jendela 150ms di atas), paksa
      // tulis segera supaya tidak ada data yang hilang.
      function _flushPendingSave() {
        if (_saveDebounceTimer) {
          clearTimeout(_saveDebounceTimer);
          _saveDebounceTimer = null;
          _origSaveLocalData2();
        }
      }
      window.addEventListener('beforeunload', _flushPendingSave);
      window.addEventListener('pagehide', _flushPendingSave);
      document.addEventListener('visibilitychange', function() {
        if (document.visibilityState === 'hidden') _flushPendingSave();
      });
    }
  })();
  

  

  // ============================================================
  // ADDITIF — PASTIKAN TRANSAKSI TERBARU SELALU DI PALING ATAS
  // (termasuk sesama transaksi di TANGGAL yang sama)
  // Tidak mengubah/menghapus fungsi, variabel, struktur data, atau
  // logika asli. allTrxList, submitTrx, syncFromGAS, loadTransaksi,
  // saveLocalData semuanya TETAP ADA & TETAP jalan apa adanya.
  //
  // Akar masalah: pengurutan asli pakai tanggal lalu tie-break pakai
  // ID transaksi (TRX-YYYYMMDD-XXXX), padahal XXXX itu 4 karakter
  // ACAK — jadi transaksi di tanggal yang sama urutannya acak, bukan
  // sesuai waktu input sebenarnya (data trx memang tidak menyimpan jam).
  //
  // Solusi (murni tambahan, tanpa ubah struktur trx yang sudah ada):
  //  - Simpan peta "ID transaksi -> waktu pertama kali terlihat di
  //    perangkat ini" secara TERPISAH di localStorage (key baru,
  //    tidak menyentuh key/struktur data asli).
  //  - Setiap kali saveLocalData() terpanggil (dari jalur manapun:
  //    submit transaksi baru, sync, dll), ID yang belum pernah tercatat
  //    otomatis diberi cap waktu saat itu.
  //  - Setelah loadTransaksi() asli selesai, urutkan ULANG allTrxList:
  //    tanggal tetap prioritas utama (sama seperti asli), tapi untuk
  //    tanggal yang sama, dipakai cap waktu lokal tadi (bukan ID acak)
  //    supaya transaksi yang BENAR-BENAR baru diinput selalu di atas.
  // ============================================================
  (function() {
    if (typeof loadTransaksi !== 'function' || typeof saveLocalData !== 'function') return;

    var LOCAL_ORDER_KEY = 'tirtaTrxLocalOrder';
    var _trxLocalOrder = {};
    try { _trxLocalOrder = JSON.parse(localStorage.getItem(LOCAL_ORDER_KEY) || '{}') || {}; } catch (e) { _trxLocalOrder = {}; }
    var _knownTrxIds = {};
    Object.keys(_trxLocalOrder).forEach(function(k) { _knownTrxIds[k] = true; });

    function _persistLocalOrder() {
      try {
        var keys = Object.keys(_trxLocalOrder);
        if (keys.length > 1000) { // batasi ukuran, buang cap waktu paling lama
          keys.sort(function(a, b) { return _trxLocalOrder[a] - _trxLocalOrder[b]; });
          keys.slice(0, keys.length - 1000).forEach(function(k) { delete _trxLocalOrder[k]; });
        }
        localStorage.setItem(LOCAL_ORDER_KEY, JSON.stringify(_trxLocalOrder));
      } catch (e) { /* diamkan, tidak boleh mengganggu aplikasi utama */ }
    }

    var _origSaveLocalDataForOrder = saveLocalData;
    saveLocalData = function() {
      try {
        if (Array.isArray(allTrxList)) {
          var changed = false;
          for (var i = 0; i < allTrxList.length; i++) {
            var t = allTrxList[i];
            if (t && t.id && !_knownTrxIds[t.id]) {
              _knownTrxIds[t.id] = true;
              _trxLocalOrder[t.id] = Date.now() + i * 0.001; // offset kecil biar stabil kalau banyak masuk bersamaan
              changed = true;
            }
          }
          if (changed) _persistLocalOrder();
        }
      } catch (e) { /* diamkan */ }
      return _origSaveLocalDataForOrder.apply(this, arguments);
    };

    var _origLoadTransaksiForOrder = loadTransaksi;
    loadTransaksi = function() {
      var result = _origLoadTransaksiForOrder.apply(this, arguments);
      try {
        if (Array.isArray(allTrxList)) {
          allTrxList.sort(function(a, b) {
            var dateCmp = (b.tgl || '').localeCompare(a.tgl || '');
            if (dateCmp !== 0) return dateCmp;
            // Prioritas 1: createdAt ASLI dari server (backend GAS sudah diupdate untuk
            // mengirim field ini) — akurat & konsisten di semua device.
            var ca = a.createdAt, cb = b.createdAt;
            if (ca && cb) { var cCmp = String(cb).localeCompare(String(ca)); if (cCmp !== 0) return cCmp; }
            else if (ca && !cb) return -1;
            else if (!ca && cb) return 1;
            // Prioritas 2: cap waktu lokal (untuk transaksi yang baru diinput di perangkat
            // ini sebelum sempat sinkron createdAt dari server, atau data lama sebelum
            // backend diupdate).
            var oa = _trxLocalOrder[a.id], ob = _trxLocalOrder[b.id];
            if (oa !== undefined && ob !== undefined) return ob - oa; // makin baru = makin atas
            if (oa !== undefined) return -1;
            if (ob !== undefined) return 1;
            return (b.id || '').localeCompare(a.id || ''); // fallback terakhir: sama seperti perilaku asli
          });
        }
        if (typeof renderTrxTable === 'function') renderTrxTable();
      } catch (e) { /* diamkan */ }
      return result;
    };
  })();
  

  // ============================================================
  // ADDITIF — PERBAIKI TAMPILAN STRUK WHATSAPP (Jual & Setoran)
  // Tidak mengubah/menghapus fungsi, variabel, atau logika asli.
  // doStrukWA & doSetoranWA asli TETAP ADA persis di kode, hanya
  // ditimpa (override) dari luar dengan tampilan pesan yang lebih
  // rapi & dinamis:
  //  - Garis pembatas dipanjangkan sampai ujung (26 karakter)
  //  - Nama toko dibuat rata-tengah (WhatsApp tidak punya fitur
  //    center asli untuk pesan teks, jadi dipakai trik padding
  //    spasi standar yang umum dipakai template struk WA)
  //  - Ditambahkan alamat & nomor WA di bawah nama toko
  //  - Ditambahkan "TERIMA KASIH ATAS PEMBELIAN ANDA" di baris
  //    paling bawah
  // Data transaksi/setoran yang ditampilkan (nominal, item, status,
  // dsb.) TIDAK ada yang berubah — cuma tata letaknya saja.
  // ============================================================
  (function() {
    var STORE_ADDRESS = 'WTC MANGGA DUA LANTAI UG A/53';
    var STORE_WA = 'WA : 0882-1105-8000';
    var WA_DASH_RATIO = 1.85; // '-' lebih tipis dari huruf biasa di WA, jadi butuh ±1.85x jumlah karakter biar visualnya sepanjang alamat + 3 huruf (tidak kependekan, tidak kepanjangan)
    var WA_LINE_WIDTH = Math.round((STORE_ADDRESS.length + 3) * WA_DASH_RATIO) + 5; // garis berakhir 3 huruf setelah "A/53" + 5 titik tambahan
    var WA_DIVIDER = '-'.repeat(WA_LINE_WIDTH);

    function _waCenter(text) {
      text = String(text || '');
      if (text.length >= WA_LINE_WIDTH) return text;
      var left = Math.floor((WA_LINE_WIDTH - text.length) / 2);
      return ' '.repeat(left) + text;
    }

    if (typeof doStrukWA === 'function') {
      doStrukWA = function() {
        if (!_strKData) return;
        var trx = _strKData.trx, items = _strKData.items || [];
        var storeName = (settings.namaToko || 'Tirta Kencana').toUpperCase();
        var lines = [
          '🧾 *STRUK TRANSAKSI*',
          WA_DIVIDER,
          storeName,
          STORE_ADDRESS,
          STORE_WA,
          WA_DIVIDER
        ];
        lines.push('No: *' + trx.id + '*');
        lines.push('Tgl: ' + fmtDate(trx.tgl));
        lines.push('Pelanggan: *' + (trx.customer || '-') + '*');
        if (trx.sales) lines.push('Sales: ' + trx.sales);
        lines.push('Status: *' + (trx.status === 'cod' ? 'COD' : trx.status === 'transfer' ? 'Transfer' : trx.status === 'qris' ? 'QRIS' : 'Belum Transfer') + '*');
        lines.push(WA_DIVIDER);
        items.forEach(function(it) {
          var nettPer = it.nettPer !== undefined ? it.nettPer : (it.harga || 0) - (it.discRpPer || 0);
          var sub = nettPer * (it.qty || 1);
          lines.push('💧 ' + it.nama + ' (' + it.qty + 'x Rp ' + Number(it.harga).toLocaleString('id-ID') + ')');
          if (it.discRpPer) lines.push('   Disc: -Rp ' + Number(it.discRpPer).toLocaleString('id-ID'));
          lines.push('   = Rp ' + Number(sub).toLocaleString('id-ID'));
        });
        lines.push(WA_DIVIDER);
        lines.push('Gross : Rp ' + Number(trx.gross).toLocaleString('id-ID'));
        if (trx.diskon) lines.push('Diskon: -Rp ' + Number(trx.diskon).toLocaleString('id-ID'));
        if (trx.biayaJml && trx.biayaJml > 0) lines.push((trx.biayaKet || 'Biaya Tambahan') + ': +Rp ' + Number(trx.biayaJml).toLocaleString('id-ID'));
        lines.push('*TOTAL : Rp ' + Number(trx.nett).toLocaleString('id-ID') + '*');
        lines.push(WA_DIVIDER);
        lines.push('Terima kasih atas pembelian Anda 🙏');
        window.open('https://wa.me/?text=' + encodeURIComponent(lines.join('\n')), '_blank');
      };
    }

    if (typeof doSetoranWA === 'function') {
      doSetoranWA = function() {
        if (!_lastSetoranPayload) return;
        var p = _lastSetoranPayload;
        var storeName = (settings.namaToko || 'Tirta Kencana').toUpperCase();
        var lines = [
          '🧾 *STRUK SETORAN*',
          WA_DIVIDER,
          storeName,
          STORE_ADDRESS,
          STORE_WA,
          WA_DIVIDER
        ];
        lines.push('Sales: *' + p.sales + '*');
        lines.push('Tgl: ' + fmtDate(p.tgl));
        lines.push(WA_DIVIDER);
        lines.push('Grand COD : ' + fmtRp(p.grandTotal));
        lines.push('Tagihan   : ' + fmtRp(p.tagihan));
        lines.push('Cicilan   : ' + fmtRp(p.cicilan));
        lines.push('Pengeluaran:');
        lines.push('  Makan   : -' + fmtRp(p.makan));
        lines.push('  Tips    : -' + fmtRp(p.tips));
        lines.push('  Parkir  : -' + fmtRp(p.parkir));
        lines.push('  Bensin  : -' + fmtRp(p.bensin));
        lines.push('  Flazz   : -' + fmtRp(p.flazz));
        lines.push('  Transfer: -' + fmtRp(p.transfer));
        if (p.ket1) lines.push('  ' + p.ket1 + ' : -' + fmtRp(p.jml1));
        if (p.ket2) lines.push('  ' + p.ket2 + ' : -' + fmtRp(p.jml2));
        lines.push(WA_DIVIDER);
        lines.push('*TOTAL SETORAN : ' + fmtRp(p.total) + '*');
        lines.push('Setor      : ' + fmtRp(p.setor));
        lines.push('Selisih    : ' + fmtRp(p.selisih));
        lines.push(WA_DIVIDER);
        lines.push('Terima kasih atas pembelian Anda 🙏');
        window.open('https://wa.me/?text=' + encodeURIComponent(lines.join('\n')), '_blank');
      };
    }
  })();
  